#!/usr/bin/env python3
"""Executable renderer fixtures for LaserJet II ROM-derived imaging behavior."""

from __future__ import annotations

import hashlib
import re
import textwrap
from dataclasses import dataclass
from pathlib import Path


ROOT = Path(__file__).resolve().parents[1]
FIRMWARE = ROOT / "generated" / "roms" / "ic30_ic13.bin"
RESOURCES = ROOT / "generated" / "roms" / "ic32_ic15.bin"
ANALYSIS = ROOT / "generated" / "analysis"

ABSTRACT_PAGE_ROOT_PTR = 1


def u16(data: bytes, offset: int) -> int:
    return int.from_bytes(data[offset : offset + 2], "big")


def s16(data: bytes, offset: int) -> int:
    value = u16(data, offset)
    return value - 0x10000 if value & 0x8000 else value


def s8(value: int) -> int:
    value &= 0xFF
    return value - 0x100 if value & 0x80 else value


def u32(data: bytes, offset: int) -> int:
    return int.from_bytes(data[offset : offset + 4], "big")


def require_firmware() -> bytes:
    if not FIRMWARE.exists():
        raise FileNotFoundError("Missing generated/roms/ic30_ic13.bin; run tools/generate_rom_artifacts.py first")
    return FIRMWARE.read_bytes()


def require_resources() -> bytes:
    if not RESOURCES.exists():
        raise FileNotFoundError("Missing generated/roms/ic32_ic15.bin; run tools/generate_rom_artifacts.py first")
    return RESOURCES.read_bytes()


def host_byte_fetch_state(**overrides: object) -> dict[str, object]:
    state: dict[str, object] = {
        "service_needed": False,
        "buffer_flags": 0,
        "force_no_byte": False,
        "lifo1": [],
        "data_chain": [],
        "data_chain_end_marker": False,
        "lifo2": [],
        "ring": [],
        "direct_mode": 0,
        "direct_mode1_status": 0,
        "direct_mode1_ack": 0,
        "direct_mode1_data": [],
        "direct_mode2_status": 0,
        "direct_mode2_data": [],
        "mode1_control_shadow": 0x12,
        "mode2_control_shadow": 0x20,
        "handshake_state": 0,
        "timeout_state": 1,
        "status_error": 0,
        "service_calls": 0,
        "control_1a_reports": 0,
        "data_chain_transitions": 0,
    }
    state.update(overrides)
    return state


def host_byte_fetch_via_a904(initial: dict[str, object]) -> dict[str, object]:
    state = dict(initial)
    events: list[dict[str, object]] = []

    for _ in range(8):
        if bool(state.get("service_needed")):
            state["service_calls"] = int(state.get("service_calls", 0)) + 1
            state["service_needed"] = False
            events.append({"kind": "service-retry", "helper": 0x10CC, "argument": 0x780202})
            continue

        if int(state.get("buffer_flags", 0)) != 0 and bool(state.get("force_no_byte")):
            return {
                "d7": -1,
                "source": "no-byte",
                "events": events,
                "state": state,
            }

        lifo1 = list(state.get("lifo1", []))
        if lifo1:
            value = int(lifo1.pop()) & 0xFF
            state["lifo1"] = lifo1
            return {
                "d7": value,
                "source": "first-lifo",
                "events": events + [{"kind": "first-lifo", "remaining": len(lifo1)}],
                "state": state,
            }

        if bool(state.get("data_chain_end_marker")):
            state["data_chain_end_marker"] = False
            state["data_chain_transitions"] = int(state.get("data_chain_transitions", 0)) + 1
            events.append({"kind": "data-chain-transition", "helper": 0xE22C})
            continue

        data_chain = list(state.get("data_chain", []))
        if data_chain:
            value = int(data_chain.pop(0)) & 0xFF
            state["data_chain"] = data_chain
            return {
                "d7": value,
                "source": "data-chain",
                "events": events + [{"kind": "data-chain-byte", "remaining": len(data_chain)}],
                "state": state,
            }

        lifo2 = list(state.get("lifo2", []))
        if lifo2:
            value = int(lifo2.pop()) & 0xFF
            state["lifo2"] = lifo2
            return {
                "d7": value,
                "source": "second-lifo",
                "events": events + [{"kind": "second-lifo", "remaining": len(lifo2)}],
                "state": state,
            }

        ring = list(state.get("ring", []))
        if int(state.get("direct_mode", 0)) == 0 and ring:
            value = int(ring.pop(0)) & 0xFF
            state["ring"] = ring
            return {
                "d7": value,
                "source": "ring",
                "events": events + [{"kind": "ring-byte", "remaining": len(ring)}],
                "state": state,
            }

        if int(state.get("direct_mode", 0)) == 1:
            if (int(state.get("direct_mode1_status", 0)) & 0x10) == 0:
                state["service_calls"] = int(state.get("service_calls", 0)) + 1
                events.append({"kind": "mode1-timeout-retry", "helper": 0xAA88})
                continue
            direct_data = list(state.get("direct_mode1_data", []))
            if not direct_data:
                return {
                    "d7": -1,
                    "source": "mode1-empty",
                    "events": events,
                    "state": state,
                }
            value = int(direct_data.pop(0)) & 0xFF
            state["direct_mode1_data"] = direct_data
            if value == 0x1A:
                state["control_1a_reports"] = int(state.get("control_1a_reports", 0)) + 1
                events.append({"kind": "control-1a-report", "helper": 0x9EC0})
            state["handshake_state"] = 0
            state["timeout_state"] = 0
            return {
                "d7": value,
                "source": "direct-mode-1",
                "events": events + [{
                    "kind": "mode1-handshake",
                    "status": int(state.get("direct_mode1_status", 0)),
                    "ack": int(state.get("direct_mode1_ack", 0)),
                    "control_shadow": int(state.get("mode1_control_shadow", 0)) & 0xFF,
                }],
                "state": state,
            }

        status = int(state.get("direct_mode2_status", 0))
        if (status & 0x01) == 0:
            if status & 0x80:
                state["status_error"] = int(state.get("status_error", 0)) | 0x80
            if status & 0x40:
                state["status_error"] = int(state.get("status_error", 0)) | 0x40
            state["service_calls"] = int(state.get("service_calls", 0)) + 1
            events.append({"kind": "mode2-status-retry", "status_error": int(state.get("status_error", 0))})
            continue
        direct_data = list(state.get("direct_mode2_data", []))
        if not direct_data:
            return {
                "d7": -1,
                "source": "mode2-empty",
                "events": events,
                "state": state,
            }
        value = int(direct_data.pop(0)) & 0xFF
        state["direct_mode2_data"] = direct_data
        if value == 0x1A:
            state["control_1a_reports"] = int(state.get("control_1a_reports", 0)) + 1
            events.append({"kind": "control-1a-report", "helper": 0x9EC0})
        state["handshake_state"] = 1
        state["timeout_state"] = 0
        state["mode2_control_shadow"] = int(state.get("mode2_control_shadow", 0)) | 0x40
        return {
            "d7": value,
            "source": "direct-mode-2",
            "events": events + [{
                "kind": "mode2-handshake",
                "status": status,
                "control_shadow": int(state.get("mode2_control_shadow", 0)) & 0xFF,
            }],
            "state": state,
        }

    raise AssertionError("host byte fetch model did not converge")


def fetch_stream_via_a904(initial: dict[str, object], byte_count: int) -> dict[str, object]:
    state = dict(initial)
    values: list[int] = []
    sources: list[str] = []
    events: list[dict[str, object]] = []
    for index in range(byte_count):
        result = host_byte_fetch_via_a904(state)
        value = int(result["d7"])
        if value < 0:
            raise AssertionError(f"0xa904 stream fetch returned no byte at index {index}")
        state = result["state"]
        if not isinstance(state, dict):
            raise AssertionError("0xa904 stream fetch did not return a state dictionary")
        values.append(value & 0xFF)
        sources.append(str(result["source"]))
        events.append({
            "index": index,
            "value": value & 0xFF,
            "source": result["source"],
            "events": result["events"],
        })
    return {
        "stream": bytes(values),
        "sources": sources,
        "events": events,
        "state": state,
    }


def signed_word_bytes(value: int) -> bytes:
    value &= 0xFFFF
    return value.to_bytes(2, "big")


def parse_pcl_numeric_records_via_daf0(stream: bytes, cursor_base: int = 0x7829A2) -> dict[str, object]:
    pos = 0
    records: list[dict[str, object]] = []
    scratch = bytearray()
    returned_d7: list[int] = []
    lookahead: int | None = None

    def read_byte() -> int:
        nonlocal pos
        if pos >= len(stream):
            return -1
        value = stream[pos]
        pos += 1
        return value

    def unread_byte() -> None:
        nonlocal pos
        if pos > 0:
            pos -= 1

    while True:
        flag = 0
        sign_negative = False
        integer_value = 0
        fraction_value = 0
        value = read_byte()
        while value == 0x20:
            value = read_byte()
        if value in (0x2B, 0x2D):
            scratch.append(value)
            flag = 0x81
            sign_negative = value == 0x2D
            value = read_byte()
            while value == 0x20:
                value = read_byte()
        if value == 0x2E or 0x30 <= value <= 0x39:
            flag |= 0x80
        if value == 0x30:
            while value == 0x30:
                scratch.append(value)
                value = read_byte()

        digit_budget = 6
        while 0x30 <= value <= 0x39:
            if digit_budget > 0:
                scratch.append(value)
                integer_value = integer_value * 10 + (value & 0x0F)
                digit_budget -= 1
            value = read_byte()
        if integer_value > 0x7FFF:
            integer_value = 0x7FFF
        if sign_negative:
            integer_value = -integer_value

        if value == 0x2E:
            scratch.append(value)
            value = read_byte()
            fraction_budget = 4
            while fraction_budget > 0:
                fraction_budget -= 1
                fraction_value *= 10
                if 0x30 <= value <= 0x39:
                    scratch.append(value)
                    fraction_value += value & 0x0F
                    value = read_byte()
            if sign_negative:
                fraction_value = -fraction_value
            while 0x30 <= value <= 0x39:
                value = read_byte()

        if value < 0:
            final = 0
        else:
            final = value & 0xFF
        returned = 0 if final in (0x3A, 0x3B) else final
        record_bytes = bytes([flag & 0xFF, final]) + signed_word_bytes(integer_value) + signed_word_bytes(fraction_value)
        record = {
            "record": record_bytes,
            "flag": flag & 0xFF,
            "final": final,
            "parameter": integer_value,
            "fraction": fraction_value,
            "cursor_before": cursor_base + len(records) * 6,
            "cursor_after": cursor_base + (len(records) + 1) * 6,
            "returned_d7": returned,
        }
        records.append(record)
        returned_d7.append(returned)

        lookahead = read_byte()
        if not (flag & 0x80 and 0x20 <= lookahead <= 0x3F):
            break
        unread_byte()

    return {
        "records": records,
        "record_bytes": b"".join(bytes(record["record"]) for record in records),
        "scratch": bytes(scratch),
        "returned_d7": returned_d7,
        "cursor": cursor_base + len(records) * 6,
        "lookahead": lookahead,
        "stream_pos": pos,
    }


def delay_payload_handler_via_121cc(record: bytes, handler: int) -> dict[str, object]:
    if len(record) != 6:
        raise AssertionError("0x121cc delayed handler snapshot requires one six-byte parsed command record")
    return {
        "pending_flag": 1,
        "handler": handler & 0xFFFFFF,
        "snapshot_record": bytes(record),
        "snapshot_bytes": bytes([1]) + (handler & 0xFFFFFFFF).to_bytes(4, "big") + record,
    }


def schedule_payload_handler_via_121cc(pending: dict[str, object], record: bytes, handler: int) -> dict[str, object]:
    if int(pending.get("pending_flag", 0)) == 1:
        return {
            "scheduled": False,
            "pending": pending,
        }
    delayed = delay_payload_handler_via_121cc(record, handler)
    return {
        "scheduled": True,
        "pending": delayed,
    }


def restore_delayed_payload_via_12218(pending: dict[str, object], alternate_mode: bool = False, cursor: int = 0x7829A2) -> dict[str, object]:
    if int(pending.get("pending_flag", 0)) != 1:
        return {
            "restored": False,
            "cursor_before": cursor,
            "cursor_after": cursor,
            "dispatch": None,
            "pending_after": pending,
        }
    record = bytes(pending["snapshot_record"])
    dispatch: dict[str, int | str]
    if alternate_mode:
        dispatch = {"kind": "alternate-data-wrapper", "helper": 0x12358, "wrapper": 0x1228A}
    else:
        dispatch = {"kind": "direct-handler", "handler": int(pending["handler"])}
    return {
        "restored": True,
        "record": record,
        "cursor_before": cursor,
        "cursor_after": cursor + 6,
        "dispatch": dispatch,
        "pending_after": {
            "pending_flag": 0,
            "handler": 0,
            "snapshot_record": record,
        },
    }


def consume_transparent_text_via_12452(
    record: bytes,
    payload: bytes,
    selected_context_byte: int = 0,
    local_filtering_word: int = 0,
) -> dict[str, object]:
    if len(record) != 6:
        raise AssertionError("0x12452 transparent text consume requires one six-byte parsed command record")
    byte_count = abs(s16(record, 2))
    d3_context = int(selected_context_byte) & 0xFF
    filtering_word = int(local_filtering_word) & 0xFFFF
    host_state = host_byte_fetch_state(data_chain=list(payload))
    values: list[int] = []
    routes: list[int] = []
    sources: list[str] = []
    control_hits = 0
    status = 1
    while len(values) < byte_count:
        result = host_byte_fetch_via_a904(host_state)
        value = int(result["d7"])
        if value < 0:
            status = 0
            break
        host_state = result["state"]
        if not isinstance(host_state, dict):
            raise AssertionError("0x12452 host fetch did not return a state dictionary")
        sources.append(str(result["source"]))
        value &= 0xFF
        if value == 0x1A:
            probe = host_byte_fetch_via_a904(host_state)
            probe_value = int(probe["d7"])
            if probe_value < 0:
                status = 0
                break
            host_state = probe["state"]
            if not isinstance(host_state, dict):
                raise AssertionError("0x12452 control probe did not return a state dictionary")
            sources.append(str(probe["source"]))
            if (probe_value & 0xFF) == 0x58:
                value = 0x7F
                control_hits += 1
            else:
                value = probe_value & 0xFF
        values.append(value)
        if value <= 0x1F and d3_context == 0:
            routes.append(0x00D0F0)
        elif 0x80 <= value <= 0x9F and filtering_word == 0:
            routes.append(0x00D0F0)
        else:
            routes.append(0x00D04A)
    remaining_chain = list(host_state.get("data_chain", []))
    return {
        "byte_count": byte_count,
        "selected_context_byte": d3_context,
        "local_filtering_word": filtering_word,
        "status": status,
        "values": values,
        "routes": routes,
        "sources": sources,
        "remaining_payload": remaining_chain,
        "control_hits": control_hits,
    }


def consume_display_functions_text_via_12536(
    payload: bytes,
    selected_context_byte: int = 0,
    local_filtering_word: int = 0,
) -> dict[str, object]:
    d3_context = int(selected_context_byte) & 0xFF
    filtering_word = int(local_filtering_word) & 0xFFFF
    host_state = host_byte_fetch_state(data_chain=list(payload))
    values: list[int] = []
    routes: list[int] = []
    sources: list[str] = []
    cr_post_handlers: list[int] = []
    control_hits = 0
    esc_seen = 0
    status = 1
    terminated = False
    while True:
        result = host_byte_fetch_via_a904(host_state)
        value = int(result["d7"])
        if value < 0:
            status = 0
            break
        host_state = result["state"]
        if not isinstance(host_state, dict):
            raise AssertionError("0x12536 host fetch did not return a state dictionary")
        sources.append(str(result["source"]))
        value &= 0xFF
        if value == 0x1A:
            probe = host_byte_fetch_via_a904(host_state)
            probe_value = int(probe["d7"])
            if probe_value < 0:
                status = 0
                break
            host_state = probe["state"]
            if not isinstance(host_state, dict):
                raise AssertionError("0x12536 control probe did not return a state dictionary")
            sources.append(str(probe["source"]))
            if (probe_value & 0xFF) == 0x58:
                value = 0x7F
                control_hits += 1
            else:
                value = probe_value & 0xFF
        values.append(value)
        if value <= 0x1F and d3_context == 0:
            routes.append(0x00D0F0)
        elif 0x80 <= value <= 0x9F and filtering_word == 0:
            routes.append(0x00D0F0)
        else:
            routes.append(0x00D04A)
        if value == 0x0D:
            cr_post_handlers.append(len(values) - 1)
        if value == 0x1B:
            esc_seen = 1
            continue
        if value == 0x5A and esc_seen:
            terminated = True
            break
        esc_seen = 0
    remaining_chain = list(host_state.get("data_chain", []))
    return {
        "selected_context_byte": d3_context,
        "local_filtering_word": filtering_word,
        "status": status,
        "terminated": terminated,
        "values": values,
        "routes": routes,
        "sources": sources,
        "remaining_payload": remaining_chain,
        "control_hits": control_hits,
        "cr_post_handlers": cr_post_handlers,
    }


