def static_context_orientation_via_e860(state: dict[str, object], slot: int) -> int:
    values = dict(state.get("e860_values", {}))
    if slot in values:
        return int(values[slot])
    records = dict(state.get("context_records", {}))
    record = dict(records.get(slot, {}))
    if int(record.get("byte_4", 0)):
        return int(record.get("byte_20", 0))
    return int(record.get("byte_16", 0))


def refresh_font_context_via_e65c(state: dict[str, object], argument: int) -> dict[str, object]:
    updated = dict(state)
    updated["context_stack_entries"] = [dict(entry) for entry in state.get("context_stack_entries", [])]
    updated["events"] = list(state.get("events", []))
    updated["context_records"] = {
        int(key): dict(value)
        for key, value in dict(state.get("context_records", {})).items()
    }
    selected = int(updated.get("selector_782f06", 0)) & 1
    static_record = dict(updated.get("static_context_record", {}))
    if argument == 0:
        entries = list(updated["context_stack_entries"])
        entry = dict(entries.pop()) if entries else {
            "long_0": 0,
            "long_4": 0,
            "byte_8": 0,
            "byte_9": 0,
        }
        updated["context_stack_entries"] = entries
        updated["context_stack_ptr"] = int(updated.get("context_stack_ptr", 0x782C28)) - 0x0A
        updated["events"].append({"kind": "context-pop", "entry": dict(entry)})
    else:
        entry = dict(static_record)
        primary_orientation = static_context_orientation_via_e860(updated, 0)
        secondary_orientation = static_context_orientation_via_e860(updated, 1)
        if not int(entry.get("byte_8", 0)) and primary_orientation != int(updated.get("class_selector_782da3", 0)):
            entry["byte_8"] = 1
            updated["events"].append({
                "kind": "static-primary-refresh-by-orientation",
                "orientation": primary_orientation,
            })
        if not int(entry.get("byte_9", 0)) and secondary_orientation != int(updated.get("class_selector_782da3", 0)):
            entry["byte_9"] = 1
            updated["events"].append({
                "kind": "static-secondary-refresh-by-orientation",
                "orientation": secondary_orientation,
            })

    if int(entry.get("byte_8", 0)) == 1:
        updated["remembered_primary_782f08"] = int(updated.get("active_primary_783144", 0)) & 0xFFFF
        updated["events"].append({"kind": "call-13eb8", "slot": 0})
        if selected == 0:
            updated["dirty_782f2d"] = 1
            updated["events"].append({"kind": "dirty-set", "slot": 0})
    if int(entry.get("byte_9", 0)) == 1:
        updated["remembered_secondary_782f0a"] = int(updated.get("active_secondary_783146", 0)) & 0xFFFF
        updated["events"].append({"kind": "call-13eb8", "slot": 1})
        if selected == 1:
            updated["dirty_782f2d"] = 1
            updated["events"].append({"kind": "dirty-set", "slot": 1})

    if argument == 0:
        entry.update({"long_0": 0, "long_4": 0, "byte_8": 0, "byte_9": 0})
        updated["events"].append({"kind": "context-entry-cleared", "entry": dict(entry)})
    else:
        updated["static_context_record"] = {
            "long_0": 0,
            "long_4": 0,
            "byte_8": 0,
            "byte_9": 0,
        }
        updated["events"].append({"kind": "static-context-cleared"})

    updated["events"].append({"kind": "call-c428", "slot": selected})
    if int(updated.get("context_install_status", 1)) == 0:
        records = dict(updated["context_records"])
        selected_record = dict(records.get(selected, {}))
        selected_record["long_0"] = int(updated.get("context_long_782c80", 0)) & 0xFFFFFFFF
        records[selected] = selected_record
        updated["context_records"] = records
        if selected == 0:
            updated["active_primary_783144"] = int(updated.get("context_word_782c84", 0)) & 0xFFFF
            updated["remembered_primary_782f08"] = int(updated.get("context_word_782c84", 0)) & 0xFFFF
        else:
            updated["active_secondary_783146"] = int(updated.get("context_word_782c84", 0)) & 0xFFFF
            updated["remembered_secondary_782f0a"] = int(updated.get("context_word_782c84", 0)) & 0xFFFF
        updated["last_context_selector_7828de"] = selected
        updated["candidate_slot_7828a8"] = (int(updated.get("context_long_782c80", 0)) & 0x00FFFFFF) | 0x80000000
        updated["dirty_782f2d"] = 1
        updated["events"].extend([
            {"kind": "context-install-empty", "slot": selected},
            {"kind": "call-1b4c0", "argument": int(updated.get("context_long_782c80", 0))},
            {"kind": "call-144d2"},
            {"kind": "call-14c64"},
            {"kind": "dirty-set", "slot": selected},
            {"kind": "call-c428", "slot": selected},
        ])
    updated["events"].append({"kind": "call-1b04c"})
    updated["dirty_782f2d"] = 0
    updated["events"].append({"kind": "dirty-cleared"})
    return updated


def replay_macro_frame_payload_via_a904(frame: dict[str, object], outer_byte: int | None = None) -> dict[str, object]:
    payload = bytes(frame.get("payload", b""))
    byte_count = int(frame.get("byte_count", len(payload)))
    if byte_count != len(payload):
        raise AssertionError("macro data-chain frame byte count must match payload length in fixture")

    state = host_byte_fetch_state(data_chain=list(payload), direct_mode=0)
    fetches: list[dict[str, object]] = []
    replayed = bytearray()
    for _ in range(byte_count):
        fetch = host_byte_fetch_via_a904(state)
        fetches.append({
            "d7": fetch["d7"],
            "source": fetch["source"],
            "events": fetch["events"],
        })
        if fetch["source"] != "data-chain":
            raise AssertionError("macro data-chain replay expected payload byte source")
        replayed.append(int(fetch["d7"]) & 0xFF)
        state = fetch["state"]
        assert isinstance(state, dict)

    outer_fetch = None
    if outer_byte is not None:
        outer_state = dict(state)
        outer_state["data_chain_end_marker"] = True
        outer_state["lifo2"] = [outer_byte & 0xFF]
        outer = host_byte_fetch_via_a904(outer_state)
        outer_fetch = {
            "d7": outer["d7"],
            "source": outer["source"],
            "events": outer["events"],
        }
        state = outer["state"]
        assert isinstance(state, dict)

    return {
        "frame": frame,
        "stream": bytes(replayed),
        "fetches": fetches,
        "outer_fetch": outer_fetch,
        "state": state,
    }


def apply_macro_control_via_dd08(state: dict[str, object], parameter: int, final_byte: int = 0x58) -> dict[str, object]:
    updated = dict(state)
    updated["records"] = [dict(record) for record in state["records"]]
    updated["data_chain_frames"] = list(state.get("data_chain_frames", []))
    updated["data_chain_frame_metadata"] = list(state.get("data_chain_frame_metadata", []))
    updated["environment_snapshots"] = list(state.get("environment_snapshots", []))
    updated["context_stack_entries"] = list(state.get("context_stack_entries", []))
    updated["events"] = list(state.get("events", []))
    selector = abs(int(parameter))
    current_id = int(updated.get("current_macro_id", 0)) & 0xFFFF
    lookup = find_macro_record_via_e0a4(updated, current_id)
    status = int(lookup["status"])
    index = lookup["index"]

    current_chain_active = int(updated.get("current_data_chain_byte_9", 0)) != 0
    if current_chain_active and selector not in (2, 3):
        updated["events"].append({"kind": "macro-control-ignored", "selector": selector, "reason": "active-data-chain"})
        return updated
    if int(updated.get("alternate_mode", 0)) == 1 and selector != 1:
        updated["events"].append({"kind": "macro-control-ignored", "selector": selector, "reason": "alternate-mode"})
        return updated

    if selector == 0:
        if index is None:
            updated["macro_error"] = 1
            updated["alternate_mode"] = 1
            updated["events"].append({"kind": "macro-start-failed", "status": status})
            return updated
        updated["records"][index] = macro_record(
            b"\x1b&f" if final_byte == 0x78 else b"\x00",
            macro_id=current_id,
        )
        updated["current_record"] = index
        updated["alternate_mode"] = 1
        updated["macro_error"] = 0
        updated["events"].append({"kind": "macro-start", "status": status, "index": index, "auto_prefix": final_byte == 0x78})
        return updated

    if selector == 1:
        if int(updated.get("alternate_mode", 0)) != 1:
            return updated
        if int(updated.get("macro_error", 0)) == 0 and index is not None:
            payload = bytes(updated["records"][index].get("payload", b""))
            if len(payload) == 1 or payload == b"\x1b&f":
                updated["records"][index] = macro_record()
                updated["events"].append({"kind": "macro-stop-cleared-empty", "index": index})
            else:
                updated["events"].append({"kind": "macro-stop-kept", "index": index, "payload": payload})
        updated["macro_error"] = 0
        updated["alternate_mode"] = 0
        return updated

    if selector in (2, 3):
        if index is not None and status == 1 and bytes(updated["records"][index].get("payload", b"")):
            execute_macro_data_chain_via_e418(updated, index, selector)
        return updated

    if selector == 4:
        if status == 1:
            updated["parser_mode"] = 1
            updated["overlay_macro_id"] = current_id
            updated["events"].append({"kind": "macro-overlay-enable", "id": current_id})
        else:
            updated["parser_mode"] = 0
        return updated

    if selector == 5:
        updated["parser_mode"] = 0
        updated["events"].append({"kind": "macro-overlay-disable"})
        return updated

    if selector == 6:
        for record_index in range(len(updated["records"])):
            clear_macro_record_via_dfba(updated, record_index)
        updated["parser_mode"] = 0
        updated["events"].append({"kind": "macro-delete-all"})
        return updated

    if selector == 7:
        for record_index, record in enumerate(list(updated["records"])):
            if not bool(dict(record).get("permanent", False)):
                clear_macro_record_via_dfba(updated, record_index)
        updated["events"].append({"kind": "macro-delete-temporary"})
        return updated

    if selector == 8:
        if index is not None:
            clear_macro_record_via_dfba(updated, index)
            updated["events"].append({"kind": "macro-delete-current", "index": index})
        return updated

    if selector == 9:
        if index is not None and status == 1:
            updated["records"][index]["permanent"] = False
            updated["events"].append({"kind": "macro-make-temporary", "index": index})
        return updated

    if selector == 10:
        if index is not None and status == 1:
            updated["records"][index]["permanent"] = True
            updated["events"].append({"kind": "macro-make-permanent", "index": index})
        return updated

    updated["events"].append({"kind": "macro-control-ignored", "selector": selector, "reason": "selector-out-of-range"})
    return updated


def append_macro_definition_payload(state: dict[str, object], payload: bytes) -> dict[str, object]:
    updated = dict(state)
    updated["records"] = [dict(record) for record in state["records"]]
    updated["events"] = list(state.get("events", []))
    current_record = updated.get("current_record")
    if current_record is None:
        updated["macro_error"] = 1
        updated["events"].append({"kind": "macro-definition-payload-dropped", "payload": payload})
        return updated

    index = int(current_record)
    existing = bytes(updated["records"][index].get("payload", b""))
    if existing == b"\x00":
        existing = b""
    updated["records"][index]["payload"] = existing + payload
    updated["events"].append({
        "kind": "macro-definition-payload",
        "index": index,
        "payload": payload,
        "record_payload": updated["records"][index]["payload"],
    })
    return updated


def render_macro_command_stream_via_e112_dd08(stream: bytes, initial_state: dict[str, object] | None = None) -> dict[str, object]:
    state = macro_state() if initial_state is None else dict(initial_state)
    state["records"] = [dict(record) for record in state["records"]]
    state["data_chain_frames"] = list(state.get("data_chain_frames", []))
    state["data_chain_frame_metadata"] = list(state.get("data_chain_frame_metadata", []))
    state["environment_snapshots"] = list(state.get("environment_snapshots", []))
    state["context_stack_entries"] = list(state.get("context_stack_entries", []))
    state["events"] = list(state.get("events", []))
    stream_events: list[dict[str, object]] = []
    pos = 0
    while pos < len(stream):
        if int(state.get("alternate_mode", 0)) == 1 and (
            stream[pos] != 0x1B
            or pos + 2 >= len(stream)
            or stream[pos + 1] != ord("&")
            or stream[pos + 2] != ord("f")
        ):
            next_macro_command = stream.find(b"\x1b&f", pos + 1)
            if next_macro_command < 0:
                next_macro_command = len(stream)
            payload = stream[pos:next_macro_command]
            state = append_macro_definition_payload(state, payload)
            event = dict(state["events"][-1])
            event.update({
                "sequence": payload,
                "handler": "alternate-data",
            })
            stream_events.append(event)
            pos = next_macro_command
            continue

        if stream[pos] != 0x1B:
            raise AssertionError(f"macro command stream expected ESC at offset {pos}")
        start = pos
        pos += 1
        if pos + 1 >= len(stream) or stream[pos] != ord("&") or stream[pos + 1] != ord("f"):
            raise AssertionError(f"macro command stream only models ESC &f commands at offset {start}")
        pos += 2
        while True:
            command_start = start if pos == start + 3 else pos
            if pos < len(stream) and (stream[pos] in (ord("+"), ord("-")) or chr(stream[pos]).isdigit()):
                parameter, pos = parse_pcl_decimal_parameter(stream, pos)
            else:
                parameter = 0
            if pos >= len(stream):
                raise AssertionError("macro command stream missing final byte")
            final = stream[pos]
            pos += 1
            final_upper = final & ~0x20 if ord("a") <= final <= ord("z") else final
            sequence = stream[command_start:pos]
            before_count = len(state.get("events", []))

            if final_upper == ord("Y"):
                record = bytes([0x80, final]) + signed_word_bytes(parameter) + b"\x00\x00"
                state = assign_macro_id_via_e112(record, state)
                event = {
                    "kind": "macro-id",
                    "sequence": sequence,
                    "parameter": parameter,
                    "handler": 0x00E112,
                    "chained": bool(ord("a") <= final <= ord("z")),
                    "current_macro_id": state["current_macro_id"],
                }
                stream_events.append(event)
                events = list(state.get("events", []))
                events.append(event)
                state["events"] = events
            elif final_upper == ord("X"):
                state = apply_macro_control_via_dd08(state, parameter, final_byte=final)
                events = list(state.get("events", []))
                for event_index in range(before_count, len(events)):
                    event = dict(events[event_index])
                    event.update({
                        "sequence": sequence,
                        "parameter": parameter,
                        "handler": 0x00DD08,
                        "chained": bool(ord("a") <= final <= ord("z")),
                    })
                    events[event_index] = event
                    stream_events.append(event)
                state["events"] = events
            else:
                raise AssertionError(f"unsupported macro command ESC &f#{chr(final)} at offset {command_start}")

            if not (ord("a") <= final <= ord("z")):
                break

    return {
        "stream": stream,
        "events": stream_events,
        "state": state,
    }


def resolve_builtin_glyph(resources: bytes, context: int, glyph_index: int) -> dict[str, int | bytes]:
    if not (context & 0x40000000):
        raise AssertionError(f"context 0x{context:08x} does not select the built-in offset-table form")
    firmware_address = context & 0x00FFFFFF
    if not (0x80000 <= firmware_address < 0xC0000):
        raise AssertionError(f"context 0x{context:08x} is outside the built-in resource window")
    base = firmware_address - 0x80000
    table = base + u16(resources, base + 8)
    entry = base + u32(resources, table + glyph_index * 4)
    bitmap_delta = resources[entry + 4]
    mode = resources[entry + 5]
    rows = u16(resources, entry + 6)
    width = u16(resources, entry + 8)
    span = (width + 7) // 8
    render_span = span
    if render_span & 1 and mode != 2 and render_span != 1:
        render_span += 1
    bitmap = entry + bitmap_delta
    return {
        "base": base,
        "table": table,
        "entry": entry,
        "bitmap": bitmap,
        "delta": bitmap_delta,
        "mode": mode,
        "rows": rows,
        "width": width,
        "span": span,
        "render_span": render_span,
        "sample": resources[bitmap : bitmap + min(16, rows * max(render_span, 1))],
    }


def resolve_inline_glyph(resources: bytes | bytearray, context: int, glyph_index: int) -> dict[str, int | bytes]:
    base = context & 0x00FFFFFF
    record = base + 0x40 + (glyph_index & 0xFF) * 8
    if record + 8 > len(resources):
        raise AssertionError(f"inline glyph record 0x{record:06x} is outside the fixture resource buffer")
    render_span = resources[record]
    rows = resources[record + 1]
    bitmap = base + u32(resources, record + 4)
    if render_span <= 0:
        raise AssertionError("inline glyph fixture requires a positive byte span")
    if bitmap + rows * render_span > len(resources):
        raise AssertionError(f"inline glyph bitmap 0x{bitmap:06x} is outside the fixture resource buffer")
    return {
        "base": base,
        "entry": record,
        "bitmap": bitmap,
        "delta": u32(resources, record + 4),
        "mode": 1,
        "rows": rows,
        "width": render_span * 8,
        "span": render_span,
        "render_span": render_span,
        "source_kind": "inline",
    }


def resolve_downloaded_pointer_glyph(resources: bytes | bytearray, context: int, glyph_index: int) -> dict[str, int | bytes] | None:
    base = context & 0x00FFFFFF
    table_entry = base + 0x4A + (glyph_index & 0xFF) * 4
    if table_entry + 4 > len(resources):
        return None
    record_delta = u32(resources, table_entry)
    record = base + record_delta
    if record_delta == 0 or record + 12 > len(resources):
        return None
    bitmap_delta = resources[record + 4]
    mode = resources[record + 5]
    rows = u16(resources, record + 6)
    width = u16(resources, record + 8)
    if bitmap_delta == 0 or mode not in (1, 2) or rows == 0 or width == 0:
        return None
    span = (width + 7) // 8
    render_span = span
    if render_span & 1 and mode != 2 and render_span != 1:
        render_span += 1
    bitmap = record + bitmap_delta
    if bitmap + rows * render_span > len(resources):
        return None
    return {
        "base": base,
        "entry": record,
        "bitmap": bitmap,
        "delta": bitmap_delta,
        "mode": mode,
        "rows": rows,
        "width": width,
        "span": span,
        "render_span": render_span,
        "source_kind": "downloaded-pointer",
        "table_entry": table_entry,
        "record_delta": record_delta,
    }


def resolve_compact_glyph(resources: bytes | bytearray, context: int, glyph_index: int) -> dict[str, int | bytes]:
    if context & 0x40000000:
        firmware_address = context & 0x00FFFFFF
        if 0x80000 <= firmware_address < 0xC0000:
            glyph = resolve_builtin_glyph(bytes(resources), context, glyph_index)
            glyph["source_kind"] = "builtin"
            return glyph
        downloaded = resolve_downloaded_pointer_glyph(resources, context, glyph_index)
        if downloaded is not None:
            downloaded["source_kind"] = "downloaded-offset-table"
            return downloaded
        raise AssertionError(f"offset-table glyph {glyph_index} is missing for context 0x{context:08x}")
    downloaded = resolve_downloaded_pointer_glyph(resources, context, glyph_index)
    if downloaded is not None:
        return downloaded
    return resolve_inline_glyph(resources, context, glyph_index)


def glyph_bitmap_rows(resources: bytes, glyph: dict[str, int | bytes]) -> list[str]:
    mode = int(glyph["mode"])
    if mode not in (1, 2):
        raise AssertionError(f"mode {mode} glyph bitmap decoder is not implemented")
    bitmap = int(glyph["bitmap"])
    rows = int(glyph["rows"])
    width = int(glyph["width"])
    render_span = int(glyph["render_span"])
    bitmap_bytes = resources[bitmap : bitmap + rows * render_span]
    return bitmap_bytes_to_rows(bitmap_bytes, rows, width, render_span)


def glyph_uses_trailing_plane(glyph: dict[str, int | bytes]) -> bool:
    render_span = int(glyph["render_span"])
    if render_span <= 1 or not (render_span & 1):
        return False
    source_kind = glyph.get("source_kind")
    if source_kind == "inline":
        return True
    return int(glyph["mode"]) == 2 and source_kind in (
        "downloaded-pointer",
        "downloaded-offset-table",
    )


def offset_table_base_map(resources: bytes | bytearray, context: int, host_char: int) -> dict[str, int]:
    if not (context & 0x40000000):
        raise AssertionError(f"context 0x{context:08x} does not select the offset-table form")
    address = context & 0x00FFFFFF
    base_bias = 0x80000 if 0x80000 <= address < 0xC0000 else 0
    base = address - base_bias
    first_char = u16(resources, base + 0x0E)
    last_char = u16(resources, base + 0x10)
    mapped = host_char - first_char if first_char <= host_char <= last_char else 0
    return {
        "base": base,
        "first_char": first_char,
        "last_char": last_char,
        "host_char": host_char,
        "mapped": mapped & 0xFF,
    }


def built_in_base_map(resources: bytes, context: int, host_char: int) -> dict[str, int]:
    if not (context & 0x40000000):
        raise AssertionError(f"context 0x{context:08x} does not select the built-in offset-table form")
    return offset_table_base_map(resources, context, host_char)


def offset_table_base_map_table(memory: bytes | bytearray, context: int, *, base_bias: int = 0) -> bytes:
    if not (context & 0x40000000):
        raise AssertionError(f"context 0x{context:08x} does not select the offset-table form")
    base = (context & 0x00FFFFFF) - int(base_bias)
    first_char = u16(memory, base + 0x0E)
    last_char = u16(memory, base + 0x10)
    table = bytearray(0x100)
    for host in range(max(0, first_char), min(0xFF, last_char) + 1):
        table[host] = (host - first_char) & 0xFF
    return bytes(table)


def built_in_base_map_table(resources: bytes, context: int) -> bytes:
    if not (context & 0x40000000):
        raise AssertionError(f"context 0x{context:08x} does not select the built-in offset-table form")
    return offset_table_base_map_table(resources, context, base_bias=0x80000)


def symbol_set_patch_pairs_via_14fce(data: bytes, symbol_word: int) -> dict[str, object]:
    table = 0x14FCE
    for index in range(18):
        pos = table + index * 6
        if pos + 6 > len(data):
            break
        if u16(data, pos) != (int(symbol_word) & 0xFFFF):
            continue
        pointer = u32(data, pos + 2)
        if pointer + 2 > len(data):
            return {"symbol_word": int(symbol_word) & 0xFFFF, "index": index, "pointer": pointer, "pairs": []}
        count = u16(data, pointer)
        pairs: list[tuple[int, int]] = []
        pair_pos = pointer + 2
        for _ in range(count):
            if pair_pos + 2 > len(data):
                break
            pairs.append((data[pair_pos], data[pair_pos + 1]))
            pair_pos += 2
        return {"symbol_word": int(symbol_word) & 0xFFFF, "index": index, "pointer": pointer, "pairs": pairs}
    return {"symbol_word": int(symbol_word) & 0xFFFF, "index": -1, "pointer": 0, "pairs": []}


def apply_symbol_set_patch_via_14f16(data: bytes, table: bytes, active_symbol_word: int) -> dict[str, object]:
    if len(table) != 0x100:
        raise AssertionError("0x14f16 symbol-set patch fixture requires a 256-byte map")
    patched = bytearray(table)
    word = int(active_symbol_word) & 0xFFFF
    if word == 0x0005:
        patched[:0x80] = patched[0x80:0x100]
        patched[0x80:0x100] = b"\x00" * 0x80
        return {"kind": "roman-extension", "symbol_word": word, "table": bytes(patched), "pairs": []}
    if word == 0x0015:
        patched[0x80:0x100] = b"\x00" * 0x80
        return {"kind": "ascii", "symbol_word": word, "table": bytes(patched), "pairs": []}
    patch_info = symbol_set_patch_pairs_via_14fce(data, word)
    pairs = list(patch_info["pairs"])
    if pairs:
        for dst, src in pairs:
            patched[dst] = patched[src]
        patched[0x80:0x100] = b"\x00" * 0x80
        return {
            "kind": "patch-table",
            "symbol_word": word,
            "table": bytes(patched),
            "index": patch_info["index"],
            "pointer": patch_info["pointer"],
            "pairs": pairs,
        }
    return {"kind": "unchanged", "symbol_word": word, "table": bytes(patched), "pairs": []}


def apply_selected_symbol_set_patch_via_14f16(
    data: bytes,
    table: bytes,
    *,
    selected_symbol_word: int,
    active_symbol_word: int,
) -> dict[str, object]:
    selected = int(selected_symbol_word) & 0xFFFF
    if selected != 0x0115:
        return {
            "kind": "selected-symbol-not-roman8",
            "selected_symbol_word": selected,
            "symbol_word": int(active_symbol_word) & 0xFFFF,
            "table": bytes(table),
            "pairs": [],
        }
    patched = apply_symbol_set_patch_via_14f16(data, table, active_symbol_word)
    patched["selected_symbol_word"] = selected
    return patched


def symbol_set_state(**overrides: object) -> dict[str, object]:
    state: dict[str, object] = {
        "requested_symbols": [0x0115, 0x0115],
        "active_symbols": [0x0115, 0x0115],
        "remembered_symbols": [0x0115, 0x0115],
        "default_symbols": [0x0115, 0x0115, 0x0115, 0x0115],
        "orientation": 0,
        "current_selector_782f06": 0,
        "current_page_root": 0,
        "page_root_context_slots": [0] * 16,
        "page_root_live_flags": [0] * 16,
        "current_page_context_slot_78297e": 0,
        "primary_context_782ee6": 0x440946B4,
        "secondary_context_782ef6": 0x44094B08,
        "selected_context_record_782992": 0x440946B4,
        "context_install_events": [],
        "candidate_refresh_calls": [],
        "transient_context_refresh_78298f": 0,
        "font_id_select_flag_78287b": 0,
        "dirty_flag": 0,
        "dirty_maps": 0,
        "refreshes": 0,
        "font_id_calls": [],
        "events": [],
    }
    state.update(overrides)
    return state


def symbol_set_handler(final: int) -> int:
    if ord("@") <= final <= ord("^"):
        return 0x0120BE
    raise AssertionError(f"unsupported symbol-set final byte {chr(final)!r}")


def symbol_word_from_pcl(parameter: int, final: int) -> int:
    return ((abs(int(parameter)) << 5) + int(final) - 0x40) & 0xFFFF


def current_font_context_record(slot: int) -> int:
    return 0x782EE6 + int(slot) * 0x10


def current_font_selected_context_longword(state: dict[str, object], slot: int) -> int:
    if int(slot) == 0:
        return int(state.get("primary_context_782ee6", state.get("selected_context_record_782992", 0)))
    if int(slot) == 1:
        return int(state.get("secondary_context_782ef6", state.get("selected_context_record_782992", 0)))
    return int(state.get("selected_context_record_782992", 0))


def install_page_root_context_via_c4fc(
    state: dict[str, object],
    context_record: int,
    *,
    caller: str,
) -> int:
    if int(state.get("current_page_root", 0)) == 0:
        return 0

    context_slots = list(state.get("page_root_context_slots", []))
    context_slots += [0] * (16 - len(context_slots))
    live_flags = list(state.get("page_root_live_flags", []))
    live_flags += [0] * (16 - len(live_flags))
    masked_context = int(context_record) & 0x00FFFFFF

    selected_slot = 0x11
    reason = "full"
    for slot in range(16):
        if (int(context_slots[slot]) & 0x00FFFFFF) == masked_context:
            selected_slot = slot
            reason = "existing-context"
            break
        if int(live_flags[slot]) != 1:
            selected_slot = slot
            reason = "first-inactive"
            break

    if selected_slot != 0x11:
        context_slots[selected_slot] = int(context_record)
        state["page_root_context_slots"] = context_slots[:16]

    events = state.setdefault("context_install_events", [])
    if not isinstance(events, list):
        raise AssertionError("context install events must be a list")
    events.append({
        "helper": 0x00C4FC,
        "caller": caller,
        "context_record": int(context_record),
        "selected_page_slot": selected_slot,
        "reason": reason,
    })
    return selected_slot


def install_current_font_context_via_c428(state: dict[str, object], slot: int) -> int:
    context_record = current_font_selected_context_longword(state, slot)
    if int(state.get("current_page_root", 0)) == 0:
        selected_page_slot = 0
    else:
        selected_page_slot = install_page_root_context_via_c4fc(
            state,
            context_record,
            caller="0xc428",
        )
        if selected_page_slot == 0x11:
            state["dirty_maps"] = 0
            return 0
    state["current_page_context_slot_78297e"] = selected_page_slot
    return 1


def activate_font_candidate_via_13eb8(state: dict[str, object], slot: int, reason: str) -> None:
    requested = state["requested_symbols"]
    active = state["active_symbols"]
    assert isinstance(requested, list)
    assert isinstance(active, list)
    active[slot] = int(requested[slot])
    calls = state.setdefault("candidate_refresh_calls", [])
    if not isinstance(calls, list):
        raise AssertionError("candidate refresh calls must be a list")
    calls.append({"helper": 0x013EB8, "slot": int(slot), "reason": reason})


def refresh_symbol_state_via_c580(state: dict[str, object], slot: int) -> None:
    requested = state["requested_symbols"]
    active = state["active_symbols"]
    remembered = state["remembered_symbols"]
    assert isinstance(requested, list)
    assert isinstance(active, list)
    assert isinstance(remembered, list)
    dirty = int(state.get("dirty_flag", 0))
    selector = int(state.get("current_selector_782f06", 0))

    if dirty == 1:
        if selector == slot:
            live_flags = list(state.get("page_root_live_flags", []))
            live_flags += [0] * (16 - len(live_flags))
            first_inactive = next(
                (index for index, flag in enumerate(live_flags[:16]) if int(flag) == 0),
                None,
            )
            if first_inactive is None and int(state.get("current_page_root", 0)) != 0:
                state["transient_context_refresh_78298f"] = 1
                activate_font_candidate_via_13eb8(state, slot, "full-live-page-root")
                state["transient_context_refresh_78298f"] = 0
            selected_context = int(state.get("selected_context_record_782992", current_font_context_record(slot)))
            selected_page_slot = install_page_root_context_via_c4fc(
                state,
                selected_context,
                caller="0xc580",
            )
            if selected_page_slot != 0x11:
                activate_font_candidate_via_13eb8(state, slot, "post-c4fc")
                install_current_font_context_via_c428(state, slot)
        else:
            activate_font_candidate_via_13eb8(state, slot, "selector-mismatch")
    else:
        if selector == slot:
            install_current_font_context_via_c428(state, slot)

    remembered[slot] = int(active[slot])
    state["dirty_flag"] = 0
    state["dirty_maps"] = 0
    state["refreshes"] = int(state.get("refreshes", 0)) + 1


def apply_shift_in_out_via_c68a_c6b8(
    state: dict[str, object],
    byte: int,
) -> dict[str, object]:
    if byte not in (0x0E, 0x0F):
        raise AssertionError(f"SI/SO fixture expected 0x0e or 0x0f, got 0x{byte:02x}")

    updated = dict(state)
    selector_before = int(updated.get("text_map_selector_782f06", 0)) & 0xFF
    requested_selector = 0 if byte == 0x0F else 1
    handler = 0x00C68A if byte == 0x0F else 0x00C6B8
    install_called = selector_before != requested_selector
    install_success = bool(int(updated.get("font_context_install_success", 1)))

    updated["font_context_refresh_pending_782f2d"] = 1
    if install_called:
        updated["font_context_install_calls"] = int(updated.get("font_context_install_calls", 0)) + 1
        updated["font_context_install_argument"] = requested_selector
        updated["font_context_install_handler"] = 0x00C428
        if install_success:
            install_status = None
            if "current_page_root" in updated and (
                "primary_context_782ee6" in updated
                or "secondary_context_782ef6" in updated
            ):
                install_status = install_current_font_context_via_c428(
                    updated,
                    requested_selector,
                )
                install_success = install_status == 1
                updated["font_context_install_status"] = install_status
            if install_success:
                updated["text_map_selector_782f06"] = requested_selector
                updated["current_selector_782f06"] = requested_selector
    updated["font_context_refresh_pending_782f2d"] = 0

    selector_after = int(updated.get("text_map_selector_782f06", selector_before)) & 0xFF
    event = {
        "handler": handler,
        "selector_before": selector_before,
        "selector_after": selector_after,
        "requested_selector": requested_selector,
        "install_called": install_called,
        "install_argument": requested_selector if install_called else None,
        "install_success": install_success if install_called else None,
        "pending_before": 0,
        "pending_after": int(updated["font_context_refresh_pending_782f2d"]),
    }
    if install_called and "font_context_install_status" in updated:
        event["install_status"] = updated["font_context_install_status"]
        event["current_page_context_slot_78297e"] = updated.get("current_page_context_slot_78297e", 0)
        event["page_root_context_slots"] = list(updated.get("page_root_context_slots", []))[:2]
        event["context_install_events"] = list(updated.get("context_install_events", []))
    return {
        "state": updated,
        "event": event,
    }


def apply_symbol_set_stream_via_120be_1be22(state: dict[str, object], stream: bytes) -> dict[str, object]:
    state = dict(state)
    state["requested_symbols"] = list(state["requested_symbols"])
    state["active_symbols"] = list(state["active_symbols"])
    state["remembered_symbols"] = list(state["remembered_symbols"])
    state["default_symbols"] = list(state["default_symbols"])
    state["page_root_context_slots"] = list(state.get("page_root_context_slots", []))
    state["page_root_live_flags"] = list(state.get("page_root_live_flags", []))
    state["context_install_events"] = list(state.get("context_install_events", []))
    state["candidate_refresh_calls"] = list(state.get("candidate_refresh_calls", []))
    state["font_id_calls"] = list(state.get("font_id_calls", []))
    state["events"] = list(state.get("events", []))
    pos = 0
    stream_events: list[dict[str, object]] = []
    while pos < len(stream):
        start = pos
        if pos + 2 >= len(stream) or stream[pos] != 0x1B or stream[pos + 1] not in (ord("("), ord(")")):
            raise AssertionError(f"symbol-set stream only models ESC (#A..^ / ESC )#A..^ at offset {pos}")
        slot = 0 if stream[pos + 1] == ord("(") else 1
        setup_handler = 0x01201E if slot == 0 else 0x012008
        pos += 2
        parameter, pos = parse_pcl_decimal_parameter(stream, pos)
        if pos >= len(stream):
            raise AssertionError("symbol-set stream missing final byte")
        final = stream[pos]
        pos += 1
        if not (ord("@") <= final <= ord("^")):
            raise AssertionError(f"symbol-set stream unsupported final byte {chr(final)!r}")
        requested = state["requested_symbols"]
        default_symbols = state["default_symbols"]
        assert isinstance(requested, list)
        assert isinstance(default_symbols, list)
        previous_word = int(requested[slot])
        provisional_word = symbol_word_from_pcl(parameter, final)
        kind = "symbol-set"
        handler_target = 0x01C0A4
        word = provisional_word
        font_id_call = None
        if final == ord("X"):
            kind = "font-id"
            handler_target = 0x01C066
            word = previous_word
            state["font_id_select_flag_78287b"] = 1
            font_id_call = {"slot": slot, "font_id": abs(int(parameter)), "handler": 0x017708}
            state["font_id_calls"].append(font_id_call)
        elif final == ord("@"):
            selector = abs(int(parameter))
            if selector == 0:
                handler_target = 0x01BED4
                word = int(default_symbols[int(state.get("orientation", 0)) * 2 + slot])
                kind = "default-table-slot"
            elif selector == 1:
                handler_target = 0x01BF0A
                word = int(default_symbols[int(state.get("orientation", 0)) * 2])
                kind = "default-table-primary"
            elif selector == 2:
                handler_target = 0x01BF36
                word = previous_word if slot == 0 else int(requested[0])
                kind = "copy-primary-symbol" if slot == 1 else "restore-primary-symbol"
            elif selector == 3:
                handler_target = 0x01BF74
                word = int(state.get("default_font_symbol", previous_word))
                kind = "default-font"
            else:
                handler_target = 0x01C034
                word = previous_word
                kind = "ignored-at-selector"
        requested[slot] = word
        state["dirty_flag"] = 2 if final == ord("X") else 1
        state["dirty_maps"] = 1
        dirty_before_refresh = int(state["dirty_flag"])
        dirty_maps_before_refresh = int(state["dirty_maps"])
        refresh_symbol_state_via_c580(state, slot)
        event = {
            "sequence": stream[start:pos],
            "record": bytes([0x80, final]) + signed_word_bytes(parameter) + signed_word_bytes(slot),
            "slot": slot,
            "setup_handler": setup_handler,
            "terminal_handler": symbol_set_handler(final),
            "dispatch_target": handler_target,
            "parameter": parameter,
            "final": final,
            "kind": kind,
            "dirty_before_refresh": dirty_before_refresh,
            "dirty_maps_before_refresh": dirty_maps_before_refresh,
            "font_id_call": font_id_call,
            "previous_word": previous_word,
            "provisional_word": provisional_word,
            "requested_word": word,
            "active_word": int(state["active_symbols"][slot]),
            "refreshes": int(state["refreshes"]),
        }
        state["events"].append(event)
        stream_events.append(event)
    state["stream"] = stream
    state["stream_events"] = stream_events
    return state


def default_font_symbol_tables_via_1ac0a_1af36(
    *,
    current_found: bool,
    current_orientation: int,
    current_symbol: int,
    default_candidates: list[int],
    fallback_candidates: list[int],
) -> dict[str, object]:
    if len(default_candidates) != 4 or len(fallback_candidates) != 4:
        raise AssertionError("default font table fixtures require four orientation/slot words")
    orientation = int(current_orientation) & 1
    current_word = int(current_symbol) & 0xFFFF

    default_symbols = [0, 0, 0, 0]
    default_events: list[dict[str, object]] = []
    if current_found:
        for index, address in enumerate((0x00782F1C, 0x00782F20, 0x00782F24, 0x00782F28)):
            default_symbols[index] = current_word
            default_events.append({
                "builder": 0x01AC0A,
                "source": "0x1b250-current",
                "orientation": index // 2,
                "slot": index & 1,
                "address": address,
                "word": current_word,
            })
    else:
        for orientation_index in (0, 1):
            for slot in (0, 1):
                index = orientation_index * 2 + slot
                default_symbols[index] = int(default_candidates[index]) & 0xFFFF
                default_events.append({
                    "builder": 0x01AC0A,
                    "source": "0x1ab84-synthesized",
                    "selector_78289f": orientation_index,
                    "selector_78289e": slot,
                    "orientation": orientation_index,
                    "slot": slot,
                    "address": 0x00782F1C + index * 4,
                    "word": default_symbols[index],
                })

    fallback_symbols = [0, 0, 0, 0]
    fallback_events: list[dict[str, object]] = []
    if current_found:
        for slot in (0, 1):
            index = orientation * 2 + slot
            fallback_symbols[index] = current_word
            fallback_events.append({
                "builder": 0x01AF36,
                "source": "0x1b250-current",
                "selector_78289f": orientation,
                "orientation": orientation,
                "slot": slot,
                "address": 0x00782F0C + index * 4,
                "word": current_word,
            })
        other_orientation = 1 - orientation
        for slot in (0, 1):
            index = other_orientation * 2 + slot
            fallback_symbols[index] = int(fallback_candidates[index]) & 0xFFFF
            fallback_events.append({
                "builder": 0x01AF36,
                "source": "0x1ad66-opposite-orientation",
                "selector_78289f": other_orientation,
                "selector_78289e": slot,
                "orientation": other_orientation,
                "slot": slot,
                "address": 0x00782F0C + index * 4,
                "word": fallback_symbols[index],
            })
    else:
        for orientation_index in (0, 1):
            for slot in (0, 1):
                index = orientation_index * 2 + slot
                fallback_symbols[index] = int(fallback_candidates[index]) & 0xFFFF
                fallback_events.append({
                    "builder": 0x01AF36,
                    "source": "0x1ad66-synthesized",
                    "selector_78289f": orientation_index,
                    "selector_78289e": slot,
                    "orientation": orientation_index,
                    "slot": slot,
                    "address": 0x00782F0C + index * 4,
                    "word": fallback_symbols[index],
                })

    return {
        "current_found": bool(current_found),
        "current_orientation": orientation,
        "current_symbol": current_word,
        "default_symbols": default_symbols,
        "default_events": default_events,
        "fallback_symbols": fallback_symbols,
        "fallback_events": fallback_events,
    }


def candidate_slot_lookup_via_1b4c0(
    resource_address: int,
    candidate_slots: list[dict[str, int]],
) -> dict[str, object]:
    masked_address = int(resource_address) & 0xFFFFFF
    events: list[dict[str, int | bool]] = []
    for index, candidate in enumerate(candidate_slots):
        candidate_address = int(candidate["longword"]) & 0xFFFFFF
        selected = candidate_address == masked_address
        events.append({
            "helper": 0x01B4C0,
            "index": index,
            "slot_pointer": int(candidate["slot_pointer"]),
            "candidate_address": candidate_address,
            "wanted_address": masked_address,
            "selected": selected,
        })
        if selected:
            return {
                "slot_pointer": int(candidate["slot_pointer"]),
                "events": events,
            }
    return {
        "slot_pointer": 0,
        "events": events,
    }


def default_font_current_candidate_via_1b250(
    *,
    state_78219b: int,
    state_78219c: int,
    resolved_resource_address: int,
    resolved_symbol_word: int,
    candidate_slots: list[dict[str, int]],
    boundary_7827ac: int,
) -> dict[str, object]:
    selector = int(state_78219c) & 0xFF
    kind = int(state_78219b) & 0xFF
    if selector == 0xFF:
        return {
            "found": False,
            "source": "0x1b250-disabled",
            "resolver": None,
            "selected_pointer": 0,
            "selected_resource_address": 0,
            "word": 0,
            "selector_78289f": 0,
            "events": [
                {
                    "helper": 0x01B250,
                    "state_78219b": kind,
                    "state_78219c": selector,
                    "action": "clear-current-default",
                }
            ],
        }

    resolver_address = int(resolved_resource_address) & 0xFFFFFF
    resolver_word = int(resolved_symbol_word) & 0xFFFF
    resolver = {
        "helper": 0x01B50E,
        "state_78219b": kind,
        "state_78219c": selector,
        "resource_address": resolver_address,
        "word": resolver_word,
        "resolved": resolver_address != 0,
    }
    if resolver_address == 0:
        return {
            "found": False,
            "source": "0x1b250-resolver-miss",
            "resolver": resolver,
            "selected_pointer": 0,
            "selected_resource_address": 0,
            "word": 0,
            "selector_78289f": 0,
            "events": [resolver],
        }

    slot_lookup = candidate_slot_lookup_via_1b4c0(resolver_address, candidate_slots)
    selected_pointer = int(slot_lookup["slot_pointer"])
    selector_78289f = 1 if int(boundary_7827ac) > selected_pointer else 0
    return {
        "found": selected_pointer != 0,
        "source": "0x1b250-current",
        "resolver": resolver,
        "selected_pointer": selected_pointer,
        "selected_resource_address": resolver_address if selected_pointer else 0,
        "word": resolver_word,
        "selector_78289f": selector_78289f,
        "events": [resolver] + list(slot_lookup["events"]),
    }


def default_font_candidate_admissible_via_1b7b2(
    candidate: dict[str, int],
    *,
    search_mode: int,
    candidate_word: int,
) -> dict[str, object]:
    mode = int(search_mode)
    word = int(candidate_word) & 0xFFFF
    address = int(candidate["longword"]) & 0xFFFFFF
    if mode == 3:
        selected = word in (0x0175, 0x0155, 0x0115, 0x000E)
        reason = "special-symbol" if selected else "mode3-symbol-reject"
    elif mode == 1:
        selected = 0x200000 <= address <= 0x3FFFFE and word != 0x0005
        reason = "range-1" if selected else "range-1-reject"
    elif mode == 2:
        selected = 0x400000 <= address <= 0x5FFFFE and word != 0x0005
        reason = "range-2" if selected else "range-2-reject"
    elif mode == 0:
        selected = word != 0x0005 and bool(candidate.get("downloaded_record_bit30", 0))
        reason = "downloaded-bit30" if selected else "downloaded-reject"
    else:
        selected = False
        reason = "unsupported-mode"
    return {
        "selected": selected,
        "reason": reason,
        "address": address,
        "word": word,
    }


def default_font_duplicate_filter_via_1b8b6(
    candidate: dict[str, int],
    *,
    current_selected_pointer: int,
    candidate_word: int,
    roman8_substitution_flag: bool,
) -> dict[str, object]:
    same_slot = int(current_selected_pointer) == int(candidate["slot_pointer"])
    duplicate_roman8 = (
        same_slot
        and (int(candidate_word) & 0xFFFF) == 0x0115
        and bool(roman8_substitution_flag)
    )
    return {
        "selected": not duplicate_roman8,
        "same_slot": same_slot,
        "reason": "duplicate-roman8-suppressed" if duplicate_roman8 else "admitted",
    }


def default_font_candidate_class_via_1b750(
    candidate: dict[str, int],
    *,
    search_mode: int,
    candidate_word: int,
    current_selected_pointer: int,
    roman8_substitution_flag: bool,
) -> dict[str, object]:
    admissible = default_font_candidate_admissible_via_1b7b2(
        candidate,
        search_mode=search_mode,
        candidate_word=candidate_word,
    )
    duplicate_filter = default_font_duplicate_filter_via_1b8b6(
        candidate,
        current_selected_pointer=current_selected_pointer,
        candidate_word=candidate_word,
        roman8_substitution_flag=roman8_substitution_flag,
    )
    if not bool(admissible["selected"]) or not bool(duplicate_filter["selected"]):
        class_id = 0
    elif (
        int(current_selected_pointer) == int(candidate["slot_pointer"])
        and int(search_mode) in (1, 2)
    ):
        class_id = 2
    else:
        class_id = 1
    return {
        "class": class_id,
        "admissible_reason": admissible["reason"],
        "duplicate_reason": duplicate_filter["reason"],
    }


def default_font_resolver_scan_via_1b50e(
    *,
    search_mode: int,
    requested_index: int,
    requested_symbol: int,
    current_selected_pointer: int,
    fast_probe: dict[str, int] | None,
    first_list: list[dict[str, int]],
    second_list: list[dict[str, int]],
) -> dict[str, object]:
    mode = int(search_mode)
    wanted_index = int(requested_index) & 0xFF
    requested = int(requested_symbol) & 0xFFFF
    if wanted_index == 0xFF:
        return {
            "selected_pointer": 0,
            "selected_resource_address": 0,
            "word": 0,
            "source": "0x1b50e-disabled",
            "events": [{
                "helper": 0x01B50E,
                "action": "disabled-selector",
                "search_mode": mode,
                "requested_index": wanted_index,
            }],
        }

    events: list[dict[str, object]] = []
    if mode != 0 and wanted_index == 0 and fast_probe and int(fast_probe.get("selected_pointer", 0)):
        resource_address = int(fast_probe["longword"]) & 0xFFFFFF
        word = int(fast_probe["word"]) & 0xFFFF
        events.append({
            "helper": 0x01B8EA,
            "search_mode": mode,
            "requested_index": wanted_index,
            "selected_pointer": int(fast_probe["selected_pointer"]),
            "resource_address": resource_address,
            "word": word,
            "selected": True,
        })
        return {
            "selected_pointer": int(fast_probe["selected_pointer"]),
            "selected_resource_address": resource_address,
            "word": word,
            "source": "0x1b50e-fast-probe",
            "events": events,
        }

    if mode not in (0, 1, 2, 3):
        return {
            "selected_pointer": 0,
            "selected_resource_address": 0,
            "word": 0,
            "source": "0x1b50e-unsupported-mode",
            "events": [{
                "helper": 0x01B50E,
                "action": "unsupported-mode",
                "search_mode": mode,
                "requested_index": wanted_index,
            }],
        }

    roman8_substitution_flag = requested not in (0x0115, 0x0175, 0x0155, 0x000E)
    ordinal = 1
    roman8_duplicate_pending = False
    for pass_index, candidates in enumerate((first_list, second_list)):
        for index, candidate in enumerate(candidates):
            while True:
                symbol = default_font_candidate_symbol_via_1bbfe(candidate)
                candidate_word = int(symbol["word"]) & 0xFFFF
                class_result = default_font_candidate_class_via_1b750(
                    candidate,
                    search_mode=mode,
                    candidate_word=candidate_word,
                    current_selected_pointer=current_selected_pointer,
                    roman8_substitution_flag=roman8_substitution_flag,
                )
                class_id = int(class_result["class"])
                event = {
                    "helper": 0x01B50E,
                    "pass": pass_index,
                    "index": index,
                    "ordinal": ordinal,
                    "slot_pointer": int(candidate["slot_pointer"]),
                    "resource_address": int(candidate["longword"]) & 0xFFFFFF,
                    "candidate_word": candidate_word,
                    "reader": symbol["reader"],
                    "reader_source": symbol["reader_source"],
                    "class": class_id,
                    "admissible_reason": class_result["admissible_reason"],
                    "duplicate_reason": class_result["duplicate_reason"],
                    "roman8_duplicate_pending": roman8_duplicate_pending,
                    "selected": False,
                }
                events.append(event)
                if class_id == 0:
                    roman8_duplicate_pending = False
                    break
                if class_id == 2:
                    roman8_duplicate_pending = True

                if wanted_index == ordinal:
                    word = requested if (
                        candidate_word == 0x0115
                        and roman8_substitution_flag
                        and roman8_duplicate_pending
                    ) else candidate_word
                    event["selected"] = True
                    event["word"] = word
                    return {
                        "selected_pointer": int(candidate["slot_pointer"]),
                        "selected_resource_address": int(candidate["longword"]) & 0xFFFFFF,
                        "word": word,
                        "source": "0x1b50e-scan",
                        "events": events,
                    }

                if candidate_word == 0x0115 and roman8_substitution_flag:
                    if roman8_duplicate_pending or int(current_selected_pointer) == int(candidate["slot_pointer"]):
                        roman8_duplicate_pending = False
                        ordinal += 1
                        break
                    roman8_duplicate_pending = True
                    ordinal += 1
                    continue

                ordinal += 1
                break

    return {
        "selected_pointer": 0,
        "selected_resource_address": 0,
        "word": 0,
        "source": "0x1b50e-miss",
        "events": events,
    }


