def font_id_select_via_17708(
    data: bytes,
    resources: bytes,
    memory: bytes | bytearray,
    records: list[dict[str, int]],
    candidate_slots: list[dict[str, int]],
    *,
    slot: int,
    font_id: int,
    previous_font_id_782f2e: int,
    class_selector_782da3: int,
    current_selector_782f06: int,
    active_symbols: list[int],
    current_page_root: int = 0,
    page_root_context_slots: list[int] | None = None,
    page_root_live_flags: list[int] | None = None,
    cached_state_matches: bool = False,
) -> dict[str, object]:
    selected_slot = int(slot) & 1
    new_font_id = int(font_id) & 0xFFFF
    scan = font_resource_record_scan_via_172c0(records, new_font_id)
    base_result: dict[str, object] = {
        "helper": 0x017708,
        "slot": "secondary" if selected_slot else "primary",
        "font_id": new_font_id,
        "saved_font_id_782f2e": int(previous_font_id_782f2e) & 0xFFFF,
        "written_font_id_782f2e": new_font_id,
        "restored_font_id_782f2e": int(previous_font_id_782f2e) & 0xFFFF,
        "scan": scan,
    }
    if int(scan["status"]) != 0:
        return {
            **base_result,
            "status": "scan-miss",
            "selected_pointer_7828a8": 0,
            "calls": ["0x172c0"],
        }

    record = scan["record"]
    assert isinstance(record, dict)
    payload = int(record["payload"]) & 0x00FFFFFF
    slot_lookup = candidate_slot_lookup_via_1b4c0(payload, candidate_slots)
    selected_pointer = int(slot_lookup["slot_pointer"])
    if selected_pointer == 0:
        return {
            **base_result,
            "status": "candidate-slot-miss",
            "payload": payload,
            "slot_lookup": slot_lookup,
            "selected_pointer_7828a8": 0,
            "calls": ["0x172c0", "0x1b4c0"],
        }

    selected = next(
        dict(candidate)
        for candidate in candidate_slots
        if int(candidate["slot_pointer"]) == selected_pointer
    )
    longword = int(selected["longword"]) & 0xFFFFFFFF
    bit30 = ((longword >> 30) & 1) == 1
    if bit30:
        class_byte = int(selected.get("builtin_byte_0x20", selected.get("d4_class", -1))) & 0xFF
        reader = "0x15890"
        orientation_field = "+0x20"
    else:
        class_byte = int(selected.get("inline_byte_0x16", -1)) & 0xFF
        reader = "0x158be"
        orientation_field = "+0x16"
    wanted_class = int(class_selector_782da3) & 0xFF
    if class_byte != wanted_class:
        return {
            **base_result,
            "status": "class-mismatch",
            "payload": payload,
            "slot_lookup": slot_lookup,
            "selected_pointer_7828a8": selected_pointer,
            "selected_longword": longword,
            "bit30": bit30,
            "orientation_field": orientation_field,
            "class_byte": class_byte,
            "wanted_class_782da3": wanted_class,
            "calls": ["0x172c0", "0x1b4c0"],
        }

    c4fc_result = None
    c4fc_events: list[dict[str, object]] = []
    if (int(current_selector_782f06) & 1) == selected_slot:
        page_state = symbol_set_state(
            current_page_root=int(current_page_root),
            page_root_context_slots=list(page_root_context_slots or [0] * 16),
            page_root_live_flags=list(page_root_live_flags or [0] * 16),
        )
        c4fc_result = install_page_root_context_via_c4fc(
            page_state,
            payload,
            caller="0x17708",
        )
        c4fc_events = list(page_state["context_install_events"])  # type: ignore[arg-type]
        if c4fc_result == 0x11:
            return {
                **base_result,
                "status": "context-full",
                "payload": payload,
                "slot_lookup": slot_lookup,
                "selected_pointer_7828a8": selected_pointer,
                "selected_longword": longword,
                "bit30": bit30,
                "orientation_field": orientation_field,
                "class_byte": class_byte,
                "wanted_class_782da3": wanted_class,
                "c4fc_result": c4fc_result,
                "c4fc_events": c4fc_events,
                "calls": ["0x172c0", "0x1b4c0", "0xc4fc"],
            }

    updated_active = [int(word) & 0xFFFF for word in active_symbols]
    updated_active += [0] * (2 - len(updated_active))
    if bit30:
        symbol = builtin_candidate_symbol_via_15890(selected)
        updated_active[selected_slot] = int(symbol["word"]) & 0xFFFF
        if payload >= 0x080000:
            dispatch = dispatch_selected_builtin_font_via_14c64(
                data,
                resources,
                selected,
                primary_secondary_selector=selected_slot,
                active_primary_symbol=updated_active[0],
                active_secondary_symbol=updated_active[1],
                cached_state_matches=cached_state_matches,
            )
        else:
            dispatch = dispatch_selected_offset_table_font_via_14c64(
                data,
                memory,
                selected,
                primary_secondary_selector=selected_slot,
                active_primary_symbol=updated_active[0],
                active_secondary_symbol=updated_active[1],
            )
    else:
        symbol = inline_candidate_symbol_via_158be(selected)
        updated_active[selected_slot] = int(symbol["word"]) & 0xFFFF
        dispatch = dispatch_selected_inline_font_via_14c64(
            data,
            bytes(memory),
            selected,
            primary_secondary_selector=selected_slot,
            active_primary_symbol=updated_active[0],
            active_secondary_symbol=updated_active[1],
            cached_state_matches=cached_state_matches,
        )
    return {
        **base_result,
        "status": "selected",
        "payload": payload,
        "slot_lookup": slot_lookup,
        "selected_pointer_7828a8": selected_pointer,
        "selected_longword": longword,
        "bit30": bit30,
        "orientation_field": orientation_field,
        "class_byte": class_byte,
        "wanted_class_782da3": wanted_class,
        "reader": reader,
        "symbol": symbol,
        "written_selector_7828de": selected_slot,
        "active_word_register": 0x783146 if selected_slot else 0x783144,
        "active_symbols": updated_active[:2],
        "c4fc_result": c4fc_result,
        "c4fc_events": c4fc_events,
        "dispatch": dispatch,
        "calls": [
            "0x172c0",
            "0x1b4c0",
            *(["0xc4fc"] if c4fc_result is not None else []),
            reader,
            "0x1b2fe",
            "0x14c64",
        ],
    }


def selected_font_context_update_via_144d2(selected: dict[str, int], slot: int) -> dict[str, int]:
    longword = int(selected["longword"]) & 0xFFFFFFFF
    return {
        "helper": 0x0144D2,
        "context_record": current_font_context_record(slot),
        "selected_longword": longword,
        "byte_4_bit30": (longword >> 30) & 1,
        "byte_5_bit26": (longword >> 26) & 1,
    }


def selected_font_refresh_via_13eb8(
    data: bytes,
    resources: bytes,
    windows: dict[str, object],
    *,
    slot: int,
    requested_primary: int,
    requested_secondary: int,
    active_symbols: list[int],
    remembered_primary_782f08: int,
    remembered_secondary_782f0a: int,
    fallback_table_782f0c: dict[tuple[int, int], int],
    class_selector_byte_782da3: int,
    requested_spacing: int,
    requested_pitch: int,
    requested_height: int,
    requested_style: int,
    requested_stroke: int,
    requested_typeface: int,
    cache_hit_148f8: bool = False,
    transient_context_refresh_78298f: int = 0,
) -> dict[str, object]:
    selected_slot = int(slot) & 1
    updated_active = [int(word) & 0xFFFF for word in active_symbols]
    updated_active += [0] * (2 - len(updated_active))
    saved_active_word = updated_active[selected_slot]
    calls: list[str] = ["0x148f8"]
    if cache_hit_148f8:
        return {
            "helper": 0x013EB8,
            "slot": "secondary" if selected_slot else "primary",
            "status": "cache-hit",
            "saved_active_word": saved_active_word,
            "active_symbols": updated_active[:2],
            "calls": calls,
        }

    activation = activate_candidate_window_via_1569c(
        windows,
        class_selector_byte=class_selector_byte_782da3,
    )
    calls.append("0x1569c")
    symbol_filter = filter_active_candidates_via_156de(
        activation,
        primary_secondary_selector=selected_slot,
        requested_primary=requested_primary,
        requested_secondary=requested_secondary,
        initial_normalized_flag_783f00=normalized_symbol_flag_via_15850(
            requested_secondary if selected_slot else requested_primary,
        ),
        remembered_primary_782f08=remembered_primary_782f08,
        remembered_secondary_782f0a=remembered_secondary_782f0a,
        fallback_table_782f0c=fallback_table_782f0c,
        class_selector_byte_782da3=class_selector_byte_782da3,
    )
    calls.append("0x156de")
    updated_active[selected_slot] = int(symbol_filter["active_word"]) & 0xFFFF
    current_activation = activation_with_active_slots(
        activation,
        symbol_filter["survivor_slot_pointers"],  # type: ignore[arg-type]
    )

    spacing_pitch_filter = None
    if int(symbol_filter["active_count_7827b8"]) > 1:
        spacing_pitch_filter = filter_active_candidates_by_spacing_pitch_via_153c6(
            current_activation,
            requested_spacing=requested_spacing,
            requested_pitch=requested_pitch,
        )
        calls.append("0x153c6")
        current_activation = activation_with_active_slots(
            current_activation,
            spacing_pitch_filter["survivor_slot_pointers"],  # type: ignore[arg-type]
        )

    height_filter = None
    if int(current_activation["active_count_7827b8"]) > 1:
        height_filter = filter_active_candidates_by_height_via_1519a(
            current_activation,
            requested_height=requested_height,
        )
        calls.append("0x1519a")
        current_activation = activation_with_active_slots(
            current_activation,
            height_filter["survivor_slot_pointers"],  # type: ignore[arg-type]
        )

    style_filter = None
    if int(current_activation["active_count_7827b8"]) > 1:
        style_filter = filter_active_candidates_by_style_via_147b2(
            current_activation,
            requested_style=requested_style,
        )
        calls.append("0x147b2")
        current_activation = activation_with_active_slots(
            current_activation,
            style_filter["survivor_slot_pointers"],  # type: ignore[arg-type]
        )

    stroke_filter = None
    if int(current_activation["active_count_7827b8"]) > 1:
        stroke_filter = filter_active_candidates_by_stroke_via_14758(
            current_activation,
            requested_stroke=requested_stroke,
        )
        calls.append("0x14758")
        current_activation = activation_with_active_slots(
            current_activation,
            stroke_filter["survivor_slot_pointers"],  # type: ignore[arg-type]
        )

    typeface_filter = None
    if int(current_activation["active_count_7827b8"]) > 1:
        typeface_filter = filter_active_candidates_by_typeface_via_147f4(
            current_activation,
            requested_typeface=requested_typeface,
        )
        calls.append("0x147f4")
        current_activation = activation_with_active_slots(
            current_activation,
            typeface_filter["survivor_slot_pointers"],  # type: ignore[arg-type]
        )

    chosen = choose_active_candidate_via_14398(current_activation)
    calls.append("0x14398")
    selected = next(
        dict(entry)
        for entry in current_activation["entries"]  # type: ignore[index]
        if int(entry["slot_pointer"]) == int(chosen["selected_slot_pointer_7828a8"])  # type: ignore[index]
    )
    if int(transient_context_refresh_78298f) == 1:
        updated_active[selected_slot] = saved_active_word
        return {
            "helper": 0x013EB8,
            "slot": "secondary" if selected_slot else "primary",
            "status": "transient-context-only",
            "saved_active_word": saved_active_word,
            "active_symbols": updated_active[:2],
            "selected_context_record_782992": int(selected["longword"]) & 0xFFFFFFFF,
            "activation": activation,
            "symbol_filter": symbol_filter,
            "spacing_pitch_filter": spacing_pitch_filter,
            "height_filter": height_filter,
            "style_filter": style_filter,
            "stroke_filter": stroke_filter,
            "typeface_filter": typeface_filter,
            "chosen": chosen,
            "calls": calls,
        }

    context_update = selected_font_context_update_via_144d2(selected, selected_slot)
    dispatch = dispatch_selected_builtin_font_via_14c64(
        data,
        resources,
        selected,
        primary_secondary_selector=selected_slot,
        active_primary_symbol=updated_active[0],
        active_secondary_symbol=updated_active[1],
    )
    calls.extend(["0x144d2", "0x14c64"])
    return {
        "helper": 0x013EB8,
        "slot": "secondary" if selected_slot else "primary",
        "status": "selected",
        "saved_active_word": saved_active_word,
        "active_symbols": updated_active[:2],
        "activation": activation,
        "symbol_filter": symbol_filter,
        "spacing_pitch_filter": spacing_pitch_filter,
        "height_filter": height_filter,
        "style_filter": style_filter,
        "stroke_filter": stroke_filter,
        "typeface_filter": typeface_filter,
        "chosen": chosen,
        "context_update": context_update,
        "dispatch": dispatch,
        "calls": calls,
    }


def clear_download_continuation_state(continuation: dict[str, int]) -> dict[str, int]:
    cleared = dict(continuation)
    for key in ("flag", "payload", "word_0x7827c8", "dest", "trailing_dest", "remaining", "d4_counter", "d3_counter"):
        cleared[key] = 0
    return cleared


def font_character_code_from_15a18(parameter: int) -> dict[str, int]:
    value = int(parameter)
    if value < 0:
        value = -value
    if value == 0x8000:
        value = 0x7FFF
    return {
        "current_character": value & 0xFFFF,
        "stored_word": value & 0xFFFF,
    }


def font_payload_dispatch_via_11f96(parameter: int) -> dict[str, int | str]:
    handler = 0x15D0A if (parameter & 0xFFFF) == 0 else 0x16C14
    return {
        "parameter": parameter & 0xFFFF,
        "handler": handler,
        "meaning": "font-header/download-descriptor payload" if handler == 0x15D0A else "downloaded-font/character payload",
    }


def font_payload_budget_from_delayed_command(parameter: int) -> dict[str, int]:
    budget = int(parameter)
    if budget < 0:
        budget = -budget
    return {
        "byte_budget": budget,
    }


def render_font_download_char_command_stream_via_121cc_16498(
    stream: bytes,
    header: bytes | bytearray,
    *,
    char_code: int,
    record_words: tuple[int, int, int, int],
    mode: int,
    width: int,
    rows: int,
    object_offset: int,
    allocation_ok: bool = True,
    allocation_failure_release: dict[str, object] | None = None,
) -> dict[str, object]:
    updated_header = bytes(header)
    pending: dict[str, object] = {"pending_flag": 0, "handler": 0, "snapshot_record": b""}
    events: list[dict[str, object]] = []
    pos = 0
    while pos < len(stream):
        if stream[pos] != 0x1B:
            raise AssertionError(f"font command stream expected ESC at offset {pos}")
        start = pos
        pos += 1
        if pos + 1 >= len(stream) or stream[pos] not in (ord("("), ord(")")):
            raise AssertionError(f"font command stream only models ESC (s/ESC )s commands at offset {start}")
        prefix = stream[pos]
        group = stream[pos + 1]
        if group != ord("s"):
            raise AssertionError(f"font command stream only models group s at offset {start}")
        pos += 2
        slot = 1 if prefix == ord(")") else 0
        while True:
            command_start = start if pos == start + 3 else pos
            if pos < len(stream) and (stream[pos] in (ord("+"), ord("-")) or chr(stream[pos]).isdigit()):
                parameter, pos = parse_pcl_decimal_parameter(stream, pos)
            else:
                parameter = 0
            if pos >= len(stream):
                raise AssertionError("font command stream missing final byte")
            final = stream[pos]
            pos += 1
            final_upper = final & ~0x20 if ord("a") <= final <= ord("z") else final
            if final_upper != ord("W"):
                raise AssertionError(f"font command stream only models ESC )s#W payloads, got 0x{final:02x}")

            sequence = stream[command_start:pos]
            parsed_record = bytes([
                0x81 if parameter < 0 else 0x80,
                final,
            ]) + signed_word_bytes(parameter) + b"\x00\x00"
            dispatch = font_payload_dispatch_via_11f96(parameter)
            handler = int(dispatch["handler"])
            scheduled = schedule_payload_handler_via_121cc(pending, parsed_record, handler)
            pending = scheduled["pending"]
            delayed_snapshot = pending["snapshot_bytes"]
            if ord("a") <= final <= ord("z"):
                events.append({
                    "kind": "font-payload-pending",
                    "sequence": sequence,
                    "parameter": parameter,
                    "parsed_record": parsed_record,
                    "delayed_snapshot_bytes": delayed_snapshot,
                    "delayed_scheduled": scheduled["scheduled"],
                    "delayed_handler": handler,
                    "dispatch": dispatch,
                    "chained": True,
                })
                continue

            restored = restore_delayed_payload_via_12218(pending)
            pending = restored["pending_after"]
            restored_record = restored["record"]
            byte_budget = abs(s16(restored_record, 2))
            payload_start = pos
            payload_end = pos + byte_budget
            if payload_end > len(stream):
                raise AssertionError("font command stream payload shorter than restored ESC )s#W byte count")
            payload = stream[payload_start:payload_end]
            pos = payload_end

            if handler != 0x16C14:
                events.append({
                    "kind": "font-descriptor-payload",
                    "sequence": sequence,
                    "parameter": parameter,
                    "parsed_record": parsed_record,
                    "delayed_snapshot_bytes": delayed_snapshot,
                    "delayed_scheduled": scheduled["scheduled"],
                    "restore_dispatch": restored["dispatch"],
                    "restored_record": restored["record"],
                    "delayed_handler": handler,
                    "payload_offset": payload_start,
                    "payload": payload,
                    "chained": False,
                })
                break

            installed = font_download_char_object_via_16498(
                updated_header,
                char_code,
                record_words,
                mode=mode,
                width=width,
                rows=rows,
                stream=payload,
                byte_budget=byte_budget,
                object_offset=object_offset,
                allocation_ok=allocation_ok,
                allocation_failure_release=allocation_failure_release,
            )
            if int(installed["status"]) == 1:
                updated_header = bytes(installed["header"])
            events.append({
                "kind": "font-character-payload",
                "sequence": sequence,
                "parameter": parameter,
                "parsed_record": parsed_record,
                "delayed_snapshot_bytes": delayed_snapshot,
                "delayed_scheduled": scheduled["scheduled"],
                "restore_dispatch": restored["dispatch"],
                "restored_record": restored["record"],
                "delayed_handler": handler,
                "payload_offset": payload_start,
                "payload": payload,
                "payload_length": len(payload),
                "byte_budget": byte_budget,
                "install": installed,
                "chained": False,
            })
            break

    return {
        "events": events,
        "final_header": updated_header,
        "pending": pending,
        "stream_pos": pos,
    }


def render_font_download_resource_command_stream_via_121cc_16c14(
    stream: bytes,
    *,
    records: list[dict[str, int]],
    current_id: int,
    new_payload_address: int,
    counters: dict[str, int] | None = None,
    cursors: dict[str, int] | None = None,
    candidates: list[int] | None = None,
    candidate_base: int = FONT_CANDIDATE_LIST_BASE,
    continuation: dict[str, int] | None = None,
    parser_mode: int = 0,
    allocation_ok: bool = True,
) -> dict[str, object]:
    pending: dict[str, object] = {"pending_flag": 0, "handler": 0, "snapshot_record": b""}
    events: list[dict[str, object]] = []
    pos = 0
    while pos < len(stream):
        if stream[pos] != 0x1B:
            raise AssertionError(f"font resource command stream expected ESC at offset {pos}")
        start = pos
        pos += 1
        if pos + 1 >= len(stream) or stream[pos] not in (ord("("), ord(")")):
            raise AssertionError(f"font resource command stream only models ESC (s/ESC )s commands at offset {start}")
        prefix = stream[pos]
        group = stream[pos + 1]
        if group != ord("s"):
            raise AssertionError(f"font resource command stream only models group s at offset {start}")
        pos += 2
        slot = 1 if prefix == ord(")") else 0

        while True:
            command_start = start if pos == start + 3 else pos
            if pos < len(stream) and (stream[pos] in (ord("+"), ord("-")) or chr(stream[pos]).isdigit()):
                parameter, pos = parse_pcl_decimal_parameter(stream, pos)
            else:
                parameter = 0
            if pos >= len(stream):
                raise AssertionError("font resource command stream missing final byte")
            final = stream[pos]
            pos += 1
            final_upper = final & ~0x20 if ord("a") <= final <= ord("z") else final
            if final_upper != ord("W"):
                raise AssertionError(f"font resource command stream only models ESC )s#W payloads, got 0x{final:02x}")

            sequence = stream[command_start:pos]
            parsed_record = bytes([
                0x81 if parameter < 0 else 0x80,
                final,
            ]) + signed_word_bytes(parameter) + b"\x00\x00"
            dispatch = font_payload_dispatch_via_11f96(parameter)
            handler = int(dispatch["handler"])
            scheduled = schedule_payload_handler_via_121cc(pending, parsed_record, handler)
            pending = scheduled["pending"]
            delayed_snapshot = pending["snapshot_bytes"]
            if ord("a") <= final <= ord("z"):
                events.append({
                    "kind": "font-resource-payload-pending",
                    "sequence": sequence,
                    "parameter": parameter,
                    "parsed_record": parsed_record,
                    "delayed_snapshot_bytes": delayed_snapshot,
                    "delayed_scheduled": scheduled["scheduled"],
                    "delayed_handler": handler,
                    "dispatch": dispatch,
                    "chained": True,
                })
                continue

            restored = restore_delayed_payload_via_12218(pending)
            pending = restored["pending_after"]
            restored_record = restored["record"]
            byte_budget = abs(s16(restored_record, 2))
            payload_start = pos
            payload_end = pos + byte_budget
            if payload_end > len(stream):
                raise AssertionError("font resource command stream payload shorter than restored ESC )s#W byte count")
            payload = stream[payload_start:payload_end]
            pos = payload_end

            if handler != 0x16C14:
                events.append({
                    "kind": "font-descriptor-payload",
                    "sequence": sequence,
                    "parameter": parameter,
                    "parsed_record": parsed_record,
                    "delayed_snapshot_bytes": delayed_snapshot,
                    "delayed_scheduled": scheduled["scheduled"],
                    "restore_dispatch": restored["dispatch"],
                    "restored_record": restored_record,
                    "delayed_handler": handler,
                    "payload_offset": payload_start,
                    "payload": payload,
                    "chained": False,
                })
                break

            validation = font_resource_validate_table_stream_via_16fae(bytearray(0x40), payload, byte_budget)
            allocation_valid = int(validation["status"]) == 1 and bool(allocation_ok)
            allocation = font_resource_find_allocate_via_17026(
                validation["staging"],  # type: ignore[arg-type]
                int(validation["payload_units"]),
                allocation_valid,
                validation["symbol_bytes"],  # type: ignore[arg-type]
            )
            install = None
            if int(allocation["status"]) == 1:
                payload_info = allocation["payload"]
                assert isinstance(payload_info, dict)
                payload_bytes = payload_info["payload"]
                assert isinstance(payload_bytes, bytes)
                install = downloaded_font_object_add_bookkeeping_via_16c14(
                    records,
                    current_id=current_id,
                    new_payload=new_payload_address,
                    byte20=payload_bytes[0x20],
                    byte0c=payload_bytes[0x0C],
                    counters=counters,
                    cursors=cursors,
                    continuation=continuation,
                    parser_mode=parser_mode,
                    candidates=candidates,
                    candidate_base=candidate_base,
                    allocation_ok=True,
                )
            events.append({
                "kind": "font-resource-payload",
                "sequence": sequence,
                "parameter": parameter,
                "parsed_record": parsed_record,
                "delayed_snapshot_bytes": delayed_snapshot,
                "delayed_scheduled": scheduled["scheduled"],
                "restore_dispatch": restored["dispatch"],
                "restored_record": restored_record,
                "delayed_handler": handler,
                "payload_offset": payload_start,
                "payload": payload,
                "payload_length": len(payload),
                "byte_budget": byte_budget,
                "validation": validation,
                "allocation": allocation,
                "install": install,
                "chained": False,
            })
            break

    return {
        "events": events,
        "pending": pending,
        "stream_pos": pos,
    }


def render_font_descriptor_command_stream_via_121cc_15d0a(
    stream: bytes,
    *,
    descriptor_byte_budget: int,
    records: list[dict[str, int]],
    current_id: int,
    parser_mode: int = 0,
    current_object_flags: int = 0,
    continuation: dict[str, int] | None = None,
    continuation_object_flags: int = 0,
) -> dict[str, object]:
    pending: dict[str, object] = {"pending_flag": 0, "handler": 0, "snapshot_record": b""}
    if not stream or stream[0] != 0x1B:
        raise AssertionError("font descriptor command stream expected ESC at offset 0")
    pos = 1
    if pos + 1 >= len(stream) or stream[pos] not in (ord("("), ord(")")):
        raise AssertionError("font descriptor command stream only models ESC (s/ESC )s")
    prefix = stream[pos]
    group = stream[pos + 1]
    if group != ord("s"):
        raise AssertionError("font descriptor command stream only models group s")
    pos += 2
    slot = 1 if prefix == ord(")") else 0
    if pos < len(stream) and (stream[pos] in (ord("+"), ord("-")) or chr(stream[pos]).isdigit()):
        parameter, pos = parse_pcl_decimal_parameter(stream, pos)
    else:
        parameter = 0
    if pos >= len(stream):
        raise AssertionError("font descriptor command stream missing final byte")
    final = stream[pos]
    pos += 1
    final_upper = final & ~0x20 if ord("a") <= final <= ord("z") else final
    if final_upper != ord("W"):
        raise AssertionError(f"font descriptor command stream expected W final, got 0x{final:02x}")
    parsed_record = bytes([
        0x81 if parameter < 0 else 0x80,
        final,
    ]) + signed_word_bytes(parameter) + b"\x00\x00"
    dispatch = font_payload_dispatch_via_11f96(parameter)
    handler = int(dispatch["handler"])
    if handler != 0x15D0A:
        raise AssertionError("font descriptor command stream expected zero-count descriptor handler")
    scheduled = schedule_payload_handler_via_121cc(pending, parsed_record, handler)
    pending = scheduled["pending"]
    delayed_snapshot = pending["snapshot_bytes"]
    restored = restore_delayed_payload_via_12218(pending)
    pending = restored["pending_after"]
    descriptor_offset = pos
    budget = abs(int(descriptor_byte_budget))
    descriptor_end = descriptor_offset + budget
    if descriptor_end > len(stream):
        raise AssertionError("font descriptor command stream shorter than modeled descriptor byte budget")
    descriptor = stream[descriptor_offset:descriptor_end]
    route = font_descriptor_route_via_15d0a(
        descriptor,
        byte_budget=budget,
        records=records,
        current_id=current_id,
        parser_mode=parser_mode,
        current_object_flags=current_object_flags,
        continuation=continuation,
        continuation_object_flags=continuation_object_flags,
    )
    return {
        "kind": "font-descriptor-command",
        "sequence": stream[:pos],
        "parameter": parameter,
        "parsed_record": parsed_record,
        "delayed_snapshot_bytes": delayed_snapshot,
        "delayed_scheduled": scheduled["scheduled"],
        "restore_dispatch": restored["dispatch"],
        "restored_record": restored["record"],
        "delayed_handler": handler,
        "dispatch": dispatch,
        "descriptor_offset": descriptor_offset,
        "descriptor": descriptor,
        "descriptor_byte_budget": budget,
        "route": route,
        "pending": pending,
        "stream_pos": descriptor_end,
    }


def font_descriptor_route_via_15d0a(
    stream: bytes,
    *,
    byte_budget: int,
    records: list[dict[str, int]],
    current_id: int,
    parser_mode: int = 0,
    current_object_flags: int = 0,
    continuation: dict[str, int] | None = None,
    continuation_object_flags: int = 0,
) -> dict[str, object]:
    budget = int(byte_budget)
    if budget < 0:
        budget = -budget

    def drain(reason: str, consumed: int, **extra: object) -> dict[str, object]:
        drained = max(budget - consumed, 0)
        return {
            "status": "skip-drain",
            "reason": reason,
            "initial_budget": budget,
            "consumed_prefix": consumed,
            "drained": drained,
            "remaining_budget": 0,
            **extra,
        }

    if budget < 3:
        return drain("count-below-three", 0)
    if parser_mode == 2:
        return drain("parser-mode-2", 0)
    if len(stream) < 2:
        return drain("source-exhausted-before-descriptor", len(stream))

    descriptor_kind = stream[0]
    if descriptor_kind != 4:
        return drain("descriptor-kind-rejected-by-0x169f6", 1, descriptor_kind=descriptor_kind)

    selector = stream[1]
    selector_status = 1 if selector == 0 else 2
    consumed = 2
    if selector_status == 1:
        scan = font_resource_record_scan_via_172c0(records, current_id)
        if scan["status"] != 0:
            return drain(
                "current-record-not-found",
                consumed,
                descriptor_kind=descriptor_kind,
                selector=selector,
                selector_status=selector_status,
                scan=scan,
            )
        record = scan["record"]
        assert isinstance(record, dict)
        target_payload = int(record["payload"]) & 0x00FFFFFF
        bit30 = (int(current_object_flags) >> 30) & 1
        return {
            "status": "route",
            "path": "current-record",
            "descriptor_kind": descriptor_kind,
            "selector": selector,
            "selector_status": selector_status,
            "scan": scan,
            "target_payload": target_payload,
            "object_bit30": bit30,
            "handler": 0x16498 if bit30 else 0x16606,
            "handler_meaning": "downloaded-character-object" if bit30 else "downloaded-font-resource-object",
            "initial_budget": budget,
            "consumed_prefix": consumed,
            "drained_after_route": max(budget - consumed, 0),
            "remaining_budget": 0,
        }

    if not continuation or int(continuation.get("flag", 0)) != 1:
        return drain(
            "missing-continuation",
            consumed,
            descriptor_kind=descriptor_kind,
            selector=selector,
            selector_status=selector_status,
        )
    target_payload = int(continuation.get("payload", 0)) & 0x00FFFFFF
    bit30 = (int(continuation_object_flags) >> 30) & 1
    return {
        "status": "route",
        "path": "continuation",
        "descriptor_kind": descriptor_kind,
        "selector": selector,
        "selector_status": selector_status,
        "target_payload": target_payload,
        "object_bit30": bit30,
        "handler": 0x15B9A if bit30 else 0x15C4C,
        "handler_meaning": "resume-downloaded-character-object" if bit30 else "resume-downloaded-font-resource-object",
        "initial_budget": budget,
        "consumed_prefix": consumed,
        "drained_after_route": max(budget - consumed, 0),
        "remaining_budget": 0,
    }


def downloaded_font_object_add_bookkeeping_via_16c14(
    records: list[dict[str, int]],
    *,
    current_id: int,
    new_payload: int,
    byte20: int,
    byte0c: int,
    old_payload_candidate_longword: int | None = None,
    old_payload_byte0e: int = 0,
    old_payload_byte16: int = 0,
    old_payload_byte20: int = 0,
    old_payload_first_char: int = 0,
    old_payload_last_char: int = 0,
    active_primary_context: int | None = None,
    active_secondary_context: int | None = None,
    context_stack: list[dict[str, int]] | None = None,
    default_resolver_matches: bool = False,
    counters: dict[str, int] | None = None,
    cursors: dict[str, int] | None = None,
    continuation: dict[str, int] | None = None,
    parser_mode: int = 0,
    initial_candidate_flags: int = 0,
    candidates: list[int] | None = None,
    candidate_base: int = FONT_CANDIDATE_LIST_BASE,
    allocation_ok: bool = True,
) -> dict[str, object]:
    updated_records = [dict(record) for record in records]
    updated_counters = font_counter_defaults()
    if counters:
        updated_counters.update(counters)
    updated_cursors = font_cursor_defaults()
    if cursors:
        updated_cursors.update(cursors)
    updated_continuation = dict(continuation) if continuation else None
    updated_context_stack = [dict(entry) for entry in (context_stack or [])]

    budget_action = "accept"
    scan = font_resource_record_scan_via_172c0(updated_records, current_id)
    if parser_mode == 2:
        budget_action = "skip-parser-mode"
    elif scan["status"] == 2:
        budget_action = "skip-no-record-slot"
    elif int(updated_counters["0x78278e"]) >= 0xC0:
        budget_action = "skip-candidate-limit"
    elif not allocation_ok:
        budget_action = "skip-allocation-failed"

    release = None
    record_index = scan["index"] if isinstance(scan["index"], int) else None
    replacement = None
    if budget_action not in {"skip-parser-mode", "skip-no-record-slot"} and scan["status"] == 0:
        assert record_index is not None
        old_payload = int(updated_records[record_index].get("payload", 0)) & 0x00FFFFFF
        release = font_resource_payload_release_via_1887a(
            updated_records,
            record_index=record_index,
            payload=old_payload,
            candidate_longword=(
                old_payload_candidate_longword
                if old_payload_candidate_longword is not None
                else old_payload
            ),
            payload_byte_0x0e=old_payload_byte0e,
            payload_byte_0x16=old_payload_byte16,
            payload_byte_0x20=old_payload_byte20,
            payload_first_char_0x0e=old_payload_first_char,
            payload_last_char_0x10=old_payload_last_char,
            counters=updated_counters,
            cursors=updated_cursors,
            continuation=updated_continuation,
            candidates=candidates,
            candidate_base=candidate_base,
            active_primary_context=active_primary_context,
            active_secondary_context=active_secondary_context,
            context_stack=updated_context_stack,
            default_resolver_matches=default_resolver_matches,
        )
        updated_records = list(release["records"])  # type: ignore[arg-type]
        updated_counters = dict(release["counters"])  # type: ignore[arg-type]
        updated_cursors = dict(release["cursors"])  # type: ignore[arg-type]
        updated_continuation = release["continuation"]  # type: ignore[assignment]
        updated_context_stack = list(release["context_stack"])  # type: ignore[arg-type]
        replacement = {
            "record_index": record_index,
            "released_payload": old_payload,
            "release_called": True,
            "continuation_cleared": bool(release["continuation_cleared"]),
        }

    if budget_action != "accept":
        return {
            "status": int(scan["status"]) if parser_mode != 2 else None,
            "scan": scan,
            "records": updated_records,
            "counters": updated_counters,
            "cursors": updated_cursors,
            "continuation": updated_continuation,
            "context_stack": updated_context_stack,
            "budget_action": budget_action,
            "candidate_flags": None,
            "candidate_insert": None,
            "candidates": (
                release["candidates"] if release else list(candidates) if candidates is not None else None
            ),
            "replacement": replacement,
            "release": release,
            "record_index": record_index,
        }

    assert record_index is not None

    candidate_insert = None
    updated_candidates = (
        list(release["candidates"])  # type: ignore[index]
        if release and release["candidates"] is not None
        else list(candidates) if candidates is not None else None
    )
    candidate_flags = int(initial_candidate_flags) & 0xFFFFFFFF
    if updated_candidates is not None:
        candidate_insert = font_candidate_object_insert_via_1bc38(
            updated_candidates,
            new_payload & 0x00FFFFFF,
            d5_arg=1,
            payload_byte_0x20=byte20,
            counters=updated_counters,
            cursors=updated_cursors,
            base=candidate_base,
        )
        if candidate_insert["status"] != "inserted":
            return {
                "status": int(scan["status"]),
                "scan": scan,
                "records": updated_records,
                "counters": updated_counters,
                "cursors": updated_cursors,
                "continuation": updated_continuation,
                "budget_action": "skip-candidate-insert-error",
                "candidate_flags": None,
                "candidate_insert": candidate_insert,
                "candidates": updated_candidates,
                "replacement": replacement,
                "release": release,
                "record_index": record_index,
            }
        updated_candidates = list(candidate_insert["candidates"])  # type: ignore[arg-type]
        candidate_flags = int(updated_candidates[int(candidate_insert["insert_index"])]) & 0xFFFFFFFF

    candidate_flags &= ~(1 << 27)
    candidate_flags &= 0xCFFFFFFF
    candidate_flags |= 1 << 30
    candidate_flags &= ~(1 << 31)
    if (byte0c & 0xFF) == 2:
        candidate_flags |= 1 << 26
    else:
        candidate_flags &= ~(1 << 26)
    if updated_candidates is not None and candidate_insert is not None:
        updated_candidates[int(candidate_insert["insert_index"])] = candidate_flags

    if (byte20 & 0xFF) == 1:
        for key in ("0x7827ac", "0x7827b0", "0x7827b4"):
            updated_cursors[key] = int(updated_cursors[key]) + 4
        updated_counters["0x782790"] = int(updated_counters["0x782790"]) + 1
        updated_counters["0x782796"] = int(updated_counters["0x782796"]) + 1
        counter_branch = "byte20-one"
    else:
        updated_counters["0x78279e"] = int(updated_counters["0x78279e"]) + 1
        updated_counters["0x782798"] = int(updated_counters["0x782798"]) + 1
        counter_branch = "byte20-other"
    updated_counters["0x78278e"] = int(updated_counters["0x78278e"]) + 1
    updated_counters["0x78278a"] = int(updated_counters["0x78278a"]) + 1
    updated_counters["0x782782"] = int(updated_counters["0x782782"]) + 1

    record = updated_records[record_index]
    record["id"] = current_id & 0xFFFF
    record["flags"] = int(record.get("flags", 0)) & ~0xE0
    record["payload"] = new_payload & 0x00FFFFFF

    return {
        "status": int(scan["status"]),
        "scan": scan,
        "records": updated_records,
        "counters": updated_counters,
        "cursors": updated_cursors,
        "continuation": updated_continuation,
        "budget_action": budget_action,
        "candidate_flags": candidate_flags,
        "candidate_insert": candidate_insert,
        "candidates": updated_candidates,
        "replacement": replacement,
        "release": release,
        "record_index": record_index,
        "counter_branch": counter_branch,
        "context_stack": updated_context_stack,
    }


def font_payload_record_lookup_via_170be(records: list[dict[str, int]], payload: int) -> dict[str, object]:
    masked_payload = int(payload) & 0x00FFFFFF
    for index, record in enumerate(records):
        if (int(record.get("payload", 0)) & 0x00FFFFFF) == masked_payload:
            record_id = int(record.get("id", 0)) & 0xFFFF
            if record_id & 0x8000:
                record_id -= 0x10000
            return {
                "status": record_id,
                "index": index,
                "address": FONT_RECORD_BASE + index * FONT_RECORD_SIZE,
                "record": dict(record),
                "masked_payload": masked_payload,
            }
    return {
        "status": -1,
        "index": None,
        "address": None,
        "record": None,
        "masked_payload": masked_payload,
    }


def assign_font_id_via_15a56(parsed_word: int) -> int:
    value = int(parsed_word)
    if value < -0x8000 or value > 0x7FFF:
        value = _signed_word(value & 0xFFFF)
    if value < 0:
        value = -value
    if value == 0x8000:
        value = 0x7FFF
    return value & 0xFFFF


def mark_current_font_record_via_17108(records: list[dict[str, int]], current_id: int, counters: dict[str, int] | None = None) -> dict[str, object]:
    updated_records = [dict(record) for record in records]
    updated_counters = {
        "0x782782": 0,
        "0x782786": 0,
    }
    if counters:
        updated_counters.update(counters)
    scan = font_resource_record_scan_via_172c0(updated_records, current_id)
    changed = False
    if scan["status"] == 0:
        index = scan["index"]
        assert isinstance(index, int)
        flags = int(updated_records[index].get("flags", 0))
        if not (flags & 0x40):
            updated_records[index]["flags"] = flags | 0x40
            updated_counters["0x782782"] = int(updated_counters["0x782782"]) - 1
            updated_counters["0x782786"] = int(updated_counters["0x782786"]) + 1
            changed = True
    return {
        "scan": scan,
        "records": updated_records,
        "counters": updated_counters,
        "changed": changed,
    }


def unmark_current_font_record_via_17150(records: list[dict[str, int]], current_id: int, counters: dict[str, int] | None = None) -> dict[str, object]:
    updated_records = [dict(record) for record in records]
    updated_counters = {
        "0x782782": 0,
        "0x782786": 0,
    }
    if counters:
        updated_counters.update(counters)
    scan = font_resource_record_scan_via_172c0(updated_records, current_id)
    changed = False
    if scan["status"] == 0:
        index = scan["index"]
        assert isinstance(index, int)
        flags = int(updated_records[index].get("flags", 0))
        if flags & 0x40:
            updated_records[index]["flags"] = flags & ~0x40
            updated_counters["0x782782"] = int(updated_counters["0x782782"]) + 1
            updated_counters["0x782786"] = int(updated_counters["0x782786"]) - 1
            changed = True
    return {
        "scan": scan,
        "records": updated_records,
        "counters": updated_counters,
        "changed": changed,
    }


def font_control_dispatch_table_via_16df6(data: bytes) -> dict[int | str, int]:
    table: dict[int | str, int] = {}
    pos = 0x16DB6
    while True:
        target = u32(data, pos)
        value = u32(data, pos + 4)
        pos += 8
        if target == 0:
            table["default"] = value
            break
        table[value] = target
    return table


def font_control_dispatch_via_16df6(
    data: bytes,
    records: list[dict[str, int]],
    *,
    current_id: int,
    value: int,
    parser_mode: int,
    counters: dict[str, int] | None = None,
) -> dict[str, object]:
    table = font_control_dispatch_table_via_16df6(data)
    target = table.get(value, table["default"])
    suppressed = parser_mode == 2 and value in (0, 1, 2, 3, 6)
    if target == 0x16E7E:
        result = unmark_current_font_record_via_17150(records, current_id, counters)
        action = "unmark-current"
    elif target == 0x16E86:
        result = mark_current_font_record_via_17108(records, current_id, counters)
        action = "mark-current"
    elif suppressed:
        result = {
            "records": [dict(record) for record in records],
            "counters": dict(counters) if counters else {"0x782782": 0, "0x782786": 0},
            "changed": False,
        }
        action = "suppressed"
    elif target == table["default"]:
        result = {
            "records": [dict(record) for record in records],
            "counters": dict(counters) if counters else {"0x782782": 0, "0x782786": 0},
            "changed": False,
        }
        action = "noop"
    else:
        result = {
            "records": [dict(record) for record in records],
            "counters": dict(counters) if counters else {"0x782782": 0, "0x782786": 0},
            "changed": False,
        }
        action = "dispatch-only"
    return {
        "value": value,
        "target": target,
        "action": action,
        "suppressed": suppressed,
        "result": result,
    }


def font_resource_validate_via_16fae(validator_statuses: list[int], symbol_stream: bytes, budget: int) -> dict[str, object]:
    table_base = 0x16EAE
    copied = bytearray()
    visited: list[dict[str, int]] = []
    for index in range(32):
        table_address = table_base + index * 8
        d5 = index + 1
        status = int(validator_statuses[index]) if index < len(validator_statuses) else 0
        visited.append({
            "index": index,
            "d5": d5,
            "table_address": table_address,
            "status": status,
        })
        if status != 1:
            return {
                "status": 0,
                "failed_index": index,
                "failed_d5": d5,
                "visited": visited,
                "budget": budget,
                "symbol_count": 0,
                "symbol_bytes": bytes(copied),
            }

    remaining_budget = int(budget)
    stream_index = 0
    while remaining_budget > 0 and len(copied) < 16 and stream_index < len(symbol_stream):
        copied.append(symbol_stream[stream_index])
        stream_index += 1
        remaining_budget -= 1

    return {
        "status": 1,
        "failed_index": None,
        "failed_d5": None,
        "visited": visited,
        "budget": remaining_budget,
        "symbol_count": len(copied),
        "symbol_bytes": bytes(copied),
    }


def _signed_word(value: int) -> int:
    value &= 0xFFFF
    return value - 0x10000 if value & 0x8000 else value


def _signed_byte(value: int) -> int:
    value &= 0xFF
    return value - 0x100 if value & 0x80 else value


def font_resource_validate_table_stream_via_16fae(staging: bytes | bytearray, stream: bytes, budget: int) -> dict[str, object]:
    updated = bytearray(staging)
    if len(updated) < 0x32:
        raise AssertionError("font resource validation staging buffer must include copied byte +0x31")
    cursor = 0
    remaining_budget = int(budget)
    payload_units = 0x100
    visited: list[dict[str, int]] = []

    def read_byte() -> int:
        nonlocal cursor, remaining_budget
        if remaining_budget <= 0:
            return 0
        value = stream[cursor] if cursor < len(stream) else 0
        cursor += 1
        remaining_budget -= 1
        return value

    def read_value(reader: int) -> int:
        if reader == 0x1599C:
            return read_byte()
        if reader == 0x159B6:
            return _signed_byte(read_byte())
        high = read_byte()
        low = read_byte()
        word = (high << 8) | low
        if reader == 0x159D4:
            return word
        if reader == 0x159F6:
            return _signed_word(word)
        raise AssertionError(f"unmodeled 0x16fae reader 0x{reader:06x}")

    def apply_predicate(predicate: int, value: int) -> int:
        nonlocal payload_units
        if predicate == 0x17358:
            return 1
        if predicate == 0x17362:
            setup = font_resource_setup_type_via_17362(updated, value)
            updated[:] = setup["staging"]
            payload_units = int(setup["payload_units"])
            return int(setup["status"])
        if predicate == 0x173D0:
            if value > 0x1067:
                return 0
            updated[0x16:0x18] = (value & 0xFFFF).to_bytes(2, "big")
            return 1
        if predicate == 0x173FE:
            if value <= 0 or value > 0x1068:
                return 0
            updated[0x12:0x14] = (value & 0xFFFF).to_bytes(2, "big")
            return 1
        if predicate == 0x17430:
            if value <= 0 or value > 0x1068:
                return 0
            updated[0x14:0x16] = (value & 0xFFFF).to_bytes(2, "big")
            first_code = u16(updated, 0x16)
            if first_code > value - 1:
                return 0
            updated[0x18:0x1A] = ((value - first_code - 1) & 0xFFFF).to_bytes(2, "big")
            return 1
        if predicate == 0x1749E:
            if value > 1:
                return 0
            updated[0x20] = value & 0xFF
            return 1
        if predicate == 0x174CC:
            updated[0x21] = 0 if value == 0 else 1
            return 1
        if predicate == 0x17502:
            updated[0x22:0x24] = (value & 0xFFFF).to_bytes(2, "big")
            return 1
        if predicate == 0x1751A:
            updated[0x24:0x26] = (min(value, 0x41A0) & 0xFFFF).to_bytes(2, "big")
            return 1
        if predicate == 0x1754A:
            updated[0x28:0x2A] = (min(value, 0x2AAA) & 0xFFFF).to_bytes(2, "big")
            return 1
        if predicate == 0x1757A:
            rounded = (value + 2) >> 2
            height = u16(updated, 0x14)
            if rounded > height:
                rounded = height
            updated[0x2C:0x2E] = ((rounded << 2) & 0xFFFF).to_bytes(2, "big")
            return 1
        if predicate == 0x175C2:
            updated[0x2F] = value & 0xFF
            return 1
        if predicate == 0x175DA:
            clamped = max(-7, min(7, value))
            updated[0x30] = clamped & 0xFF
            return 1
        if predicate == 0x17612:
            updated[0x31] = value & 0xFF
            return 1
        if predicate == 0x1762A:
            updated[0x1A:0x1C] = (value & 0xFFFF).to_bytes(2, "big")
            return 1
        if predicate == 0x17642:
            updated[0x0E:0x10] = b"\x00\x00"
            updated[0x10:0x12] = (0x007F if updated[0x0C] == 0 else 0x00FF).to_bytes(2, "big")
            return 1
        if predicate == 0x17690:
            updated[0x26] = 0 if u16(updated, 0x24) >= 0x41A0 else value & 0xFF
            return 1
        if predicate == 0x176C2:
            clamped = value
            if u16(updated, 0x28) >= 0x2AAA and clamped > 0x80:
                clamped = 0x80
            updated[0x2A] = clamped & 0xFF
            return 1
        raise AssertionError(f"unmodeled 0x16fae predicate 0x{predicate:06x}")

    for index, (reader, predicate) in enumerate(FONT_RESOURCE_VALIDATE_TABLE):
        value = read_value(reader)
        status = apply_predicate(predicate, value)
        visited.append({
            "index": index,
            "reader": reader,
            "predicate": predicate,
            "value": value,
            "status": status,
            "budget": remaining_budget,
        })
        if status != 1:
            return {
                "status": 0,
                "failed_index": index,
                "visited": visited,
                "staging": bytes(updated),
                "payload_units": payload_units,
                "budget": remaining_budget,
                "bytes_consumed": cursor,
                "symbol_count": 0,
                "symbol_bytes": b"",
            }

    symbol_bytes = bytearray()
    while remaining_budget > 0 and len(symbol_bytes) < 16:
        symbol_bytes.append(read_byte())

    return {
        "status": 1,
        "failed_index": None,
        "visited": visited,
        "staging": bytes(updated),
        "payload_units": payload_units,
        "budget": remaining_budget,
        "bytes_consumed": cursor,
        "symbol_count": len(symbol_bytes),
        "symbol_bytes": bytes(symbol_bytes),
    }


def font_resource_setup_type_via_17362(staging: bytes | bytearray, setup_type: int) -> dict[str, object]:
    updated = bytearray(staging)
    if len(updated) < 0x0D:
        raise AssertionError("font resource setup staging buffer must include byte +0x0c")
    if setup_type == 2:
        updated[0x0C] = 2
        payload_units = 0x100
        status = 1
    elif setup_type == 1:
        updated[0x0C] = 1
        payload_units = 0x100
        status = 1
    elif setup_type == 0:
        updated[0x0C] = 0
        payload_units = 0x80
        status = 1
    else:
        payload_units = 0x100
        status = 0
    return {
        "status": status,
        "staging": bytes(updated),
        "payload_units": payload_units,
    }


def font_resource_allocation_size_via_17026(payload_units: int) -> int:
    return (((int(payload_units) << 2) + 0x9B) >> 6)


def font_resource_payload_initializer_via_1719c(staging: bytes | bytearray, payload_units: int, symbol_bytes: bytes = b"") -> dict[str, object]:
    if len(staging) < 0x32:
        raise AssertionError("font resource initializer staging buffer must include copied byte +0x31")
    symbol_count = len(symbol_bytes)
    extra_offset = 0
    if symbol_count:
        extra_offset = 0x4A + (int(payload_units) << 2)
    total_size = max(0x3C, extra_offset + 2 + symbol_count)
    payload = bytearray(total_size)

    payload[0:4] = staging[0:4]
    payload[4:8] = staging[4:8]
    payload[8:10] = (0x004A).to_bytes(2, "big")
    payload[0x0C] = staging[0x0C]
    for offset in (0x0E, 0x10, 0x12, 0x14, 0x16, 0x18, 0x1A):
        payload[offset:offset + 2] = staging[offset:offset + 2]
    payload[0x20] = staging[0x20]
    payload[0x21] = staging[0x21]
    payload[0x22:0x24] = staging[0x22:0x24]
    payload[0x24:0x26] = staging[0x24:0x26]
    payload[0x26] = staging[0x26]
    payload[0x28:0x2A] = staging[0x28:0x2A]
    payload[0x2A] = staging[0x2A]
    payload[0x2C:0x2E] = staging[0x2C:0x2E]
    payload[0x2F] = staging[0x2F]
    payload[0x30] = staging[0x30]
    payload[0x31] = staging[0x31]

    if symbol_count:
        payload[0x38:0x3C] = extra_offset.to_bytes(4, "big")
        payload[extra_offset:extra_offset + 2] = symbol_count.to_bytes(2, "big")
        payload[extra_offset + 2:extra_offset + 2 + symbol_count] = symbol_bytes

    return {
        "payload": bytes(payload),
        "base_header_size": 0x4A,
        "extra_offset": extra_offset,
        "symbol_count": symbol_count,
        "symbol_bytes": symbol_bytes,
    }


def font_resource_find_allocate_via_17026(staging: bytes | bytearray, payload_units: int, valid: bool, symbol_bytes: bytes = b"") -> dict[str, object]:
    if not valid:
        return {
            "status": 0,
            "allocation_size": 0,
            "staging": bytes(staging),
            "payload": None,
        }
    updated = bytearray(staging)
    allocation_size = font_resource_allocation_size_via_17026(payload_units)
    updated[0:4] = (0x15).to_bytes(4, "big")
    updated[4:8] = allocation_size.to_bytes(4, "big")
    initialized = font_resource_payload_initializer_via_1719c(updated, payload_units, symbol_bytes)
    return {
        "status": 1,
        "allocation_size": allocation_size,
        "staging": bytes(updated),
        "payload": initialized,
    }


def resource_head_scan_via_041a(
    memory: bytes | bytearray,
    *,
    base_address: int = 0x080000,
    scan_span: int | None = None,
) -> dict[str, object]:
    span = len(memory) if scan_span is None else int(scan_span)
    probe = 0
    events: list[dict[str, object]] = []
    head_offsets: list[int] = []
    walked_records: list[dict[str, int]] = []
    boundary_crossings = 0

    def read_long(offset: int) -> int | None:
        if offset < 0 or offset + 4 > len(memory):
            return None
        return u32(memory, offset)

    for _ in range(512):
        if probe >= span:
            return {
                "status": "end",
                "head_offsets": head_offsets,
                "walked_records": walked_records,
                "events": events,
                "boundary_crossings": boundary_crossings,
                "final_probe": probe,
            }
        marker = read_long(probe)
        if marker is None:
            events.append({"kind": "source-exhausted", "probe": probe})
            return {
                "status": "source-exhausted",
                "head_offsets": head_offsets,
                "walked_records": walked_records,
                "events": events,
                "boundary_crossings": boundary_crossings,
                "final_probe": probe,
            }
        events.append({"kind": "probe", "offset": probe, "marker": marker})
        if marker != 0x48454144:
            step = 0x40000
            events.append({"kind": "probe-miss", "offset": probe, "step": step})
            probe += step
            continue

        head_offsets.append(probe)
        events.append({"kind": "head", "offset": probe})
        record = probe
        cumulative = 0
        next_probe_units = 1
        while True:
            length = read_long(record + 4)
            if length is None:
                events.append({"kind": "length-exhausted", "offset": record})
                return {
                    "status": "source-exhausted",
                    "head_offsets": head_offsets,
                    "walked_records": walked_records,
                    "events": events,
                    "boundary_crossings": boundary_crossings,
                    "final_probe": probe,
                }
            cumulative += length
            record += length
            if record >= span:
                events.append({"kind": "scan-limit", "offset": record})
                return {
                    "status": "end",
                    "head_offsets": head_offsets,
                    "walked_records": walked_records,
                    "events": events,
                    "boundary_crossings": boundary_crossings,
                    "final_probe": record,
                }
            if cumulative > 0x3FFFA:
                next_probe_units += 1
                cumulative -= 0x40000
                boundary_crossings += 1
                events.append({
                    "kind": "boundary-crossing",
                    "offset": record,
                    "next_probe_units": next_probe_units,
                    "residual": cumulative,
                })
            marker = read_long(record)
            if marker is None:
                events.append({"kind": "source-exhausted", "probe": record})
                return {
                    "status": "source-exhausted",
                    "head_offsets": head_offsets,
                    "walked_records": walked_records,
                    "events": events,
                    "boundary_crossings": boundary_crossings,
                    "final_probe": record,
                }
            if marker in (0, 0xFFFFFFFF):
                step = next_probe_units * 0x40000
                events.append({
                    "kind": "terminator",
                    "offset": record,
                    "marker": marker,
                    "step": step,
                })
                probe += step
                break
            if marker == 0x000000BE:
                be_length = read_long(record + 4)
                if be_length is None:
                    events.append({"kind": "length-exhausted", "offset": record})
                    return {
                        "status": "source-exhausted",
                        "head_offsets": head_offsets,
                        "walked_records": walked_records,
                        "events": events,
                        "boundary_crossings": boundary_crossings,
                        "final_probe": record,
                    }
                if be_length <= 7:
                    events.append({
                        "kind": "be-error",
                        "offset": record,
                        "length": be_length,
                        "error_handler": 0x00128C,
                        "d0": 0xE0,
                        "d1": 0x10,
                    })
                    return {
                        "status": "be-error",
                        "head_offsets": head_offsets,
                        "walked_records": walked_records,
                        "events": events,
                        "boundary_crossings": boundary_crossings,
                        "error": {"handler": 0x00128C, "d0": 0xE0, "d1": 0x10},
                        "final_probe": probe,
                    }
                target = base_address + record + 8
                events.append({
                    "kind": "be-jump",
                    "offset": record,
                    "length": be_length,
                    "target": target,
                })
                return {
                    "status": "jump",
                    "head_offsets": head_offsets,
                    "walked_records": walked_records,
                    "events": events,
                    "boundary_crossings": boundary_crossings,
                    "jump_target": target,
                    "final_probe": probe,
                }
            walked_records.append({
                "offset": record,
                "marker": marker,
                "length": read_long(record + 4) or 0,
            })
            events.append({
                "kind": "record",
                "offset": record,
                "marker": marker,
                "length": read_long(record + 4) or 0,
                "residual": cumulative,
            })

    raise AssertionError("0x41a HEAD scanner model exceeded iteration limit")


def scanned_builtin_record_bases(resources: bytes) -> list[int]:
    bases: list[int] = []
    cursor = 0
    seen = 0
    while cursor + 12 <= len(resources) and seen < 256:
        marker = u32(resources, cursor)
        if marker == 0x48454144:  # HEAD
            length = u32(resources, cursor + 4)
            if length <= 0:
                break
            cursor += length
            seen += 1
            continue
        if marker in (0x00000014, 0x00000015):
            length = u32(resources, cursor + 4)
            if length <= 0:
                break
            bases.append(cursor)
            cursor += length
            seen += 1
            continue
        break
    return bases


def tall_builtin_glyph_targets(resources: bytes) -> list[dict[str, int]]:
    targets: list[dict[str, int]] = []
    for base in scanned_builtin_record_bases(resources):
        first_char = u16(resources, base + 0x0E)
        last_char = u16(resources, base + 0x10)
        table = base + u16(resources, base + 8)
        for glyph_index in range(last_char - first_char + 1):
            entry = base + u32(resources, table + glyph_index * 4)
            delta = resources[entry + 4]
            mode = resources[entry + 5]
            rows = u16(resources, entry + 6)
            width = u16(resources, entry + 8)
            if rows > 0x80:
                targets.append({
                    "base": base,
                    "glyph": glyph_index,
                    "entry": entry,
                    "delta": delta,
                    "mode": mode,
                    "rows": rows,
                    "width": width,
                })
    return targets


def builtin_glyph_record_summary(resources: bytes) -> dict[str, object]:
    mode_counts: dict[int, int] = {}
    mode1_span_counts: dict[int, int] = {}
    mode1_render_span_counts: dict[int, int] = {}
    mode0_rows: set[int] = set()
    mode0_widths: set[int] = set()
    mode0_entries: set[int] = set()
    mode0_bases: set[int] = set()
    record_count = 0
    mode1_max_width = 0
    mode1_max_rows = 0
    mode1_odd_raw_span_count = 0
    wide_render_span_count = 0
    non_mode1_nonzero_delta_count = 0

    bases = scanned_builtin_record_bases(resources)
    for base in bases:
        context = 0x40000000 | (base + 0x80000)
        first_char = u16(resources, base + 0x0E)
        last_char = u16(resources, base + 0x10)
        for glyph_index in range(max(0, last_char - first_char + 1)):
            glyph = resolve_builtin_glyph(resources, context, glyph_index)
            mode = int(glyph["mode"])
            delta = int(glyph["delta"])
            rows = int(glyph["rows"])
            width = int(glyph["width"])
            span = int(glyph["span"])
            render_span = int(glyph["render_span"])
            entry = int(glyph["entry"])
            record_count += 1
            mode_counts[mode] = mode_counts.get(mode, 0) + 1
            if render_span > 0x10:
                wide_render_span_count += 1
            if mode != 1 and delta != 0:
                non_mode1_nonzero_delta_count += 1
            if mode == 1:
                mode1_span_counts[span] = mode1_span_counts.get(span, 0) + 1
                mode1_render_span_counts[render_span] = mode1_render_span_counts.get(render_span, 0) + 1
                mode1_max_width = max(mode1_max_width, width)
                mode1_max_rows = max(mode1_max_rows, rows)
                if span & 1 and span != 1:
                    mode1_odd_raw_span_count += 1
            elif mode == 0:
                mode0_rows.add(rows)
                mode0_widths.add(width)
                mode0_entries.add(entry)
                mode0_bases.add(base)

    return {
        "record_bases": len(bases),
        "glyph_records": record_count,
        "mode_counts": sorted(mode_counts.items()),
        "mode1_span_counts": sorted(mode1_span_counts.items()),
        "mode1_render_span_counts": sorted(mode1_render_span_counts.items()),
        "mode1_max_width": mode1_max_width,
        "mode1_max_rows": mode1_max_rows,
        "mode1_odd_raw_span_count": mode1_odd_raw_span_count,
        "wide_render_span_gt16_count": wide_render_span_count,
        "non_mode1_nonzero_delta_count": non_mode1_nonzero_delta_count,
        "mode0_zero_delta_count": mode_counts.get(0, 0) - non_mode1_nonzero_delta_count,
        "mode0_unique_entries": len(mode0_entries),
        "mode0_unique_bases": len(mode0_bases),
        "mode0_rows": sorted(mode0_rows),
        "mode0_widths": sorted(mode0_widths),
    }


def bitmap_bytes_to_rows(bitmap: bytes | bytearray, rows: int, width: int, stride: int) -> list[str]:
    out: list[str] = []
    for row_index in range(rows):
        row = bitmap[row_index * stride : (row_index + 1) * stride]
        bits = "".join("#" if (byte >> (7 - bit)) & 1 else "." for byte in row for bit in range(8))
        out.append(bits[:width])
    return out


def compose_set_pixel_rows(layers: list[list[str]], width: int, rows: int) -> list[str]:
    dest = [["." for _ in range(width)] for _ in range(rows)]
    for layer in layers:
        for y, row in enumerate(layer[:rows]):
            for x, pixel in enumerate(row[:width]):
                if pixel == "#":
                    dest[y][x] = "#"
    return ["".join(row) for row in dest]


def expected_line_printer_rule_raster_band_rows(glyph_rows: list[str], include_raster: bool) -> list[str]:
    rows: list[str] = []
    raster_row_bits = "##....##..####.."
    for row_index in range(28):
        row = ["."] * 40
        if row_index < len(glyph_rows):
            for x, pixel in enumerate(glyph_rows[row_index]):
                if pixel == "#":
                    row[16 + x] = "#"
        if include_raster and row_index == 12:
            for x, pixel in enumerate(raster_row_bits):
                if pixel == "#":
                    row[x] = "#"
        if 24 <= row_index < 27:
            row[24:36] = ["#"] * 12
        rows.append("".join(row))
    return rows


def write_bitmap_bits(dest: bytearray, dest_stride: int, source: bytes, rows: int, span: int, x: int, y: int) -> None:
    for row_index in range(rows):
        row_base = row_index * span
        dest_row = (y + row_index) * dest_stride
        for bit_index in range(span * 8):
            src_byte = source[row_base + bit_index // 8]
            src_mask = 0x80 >> (bit_index & 7)
            pixel = x + bit_index
            dest_offset = dest_row + pixel // 8
            if dest_offset >= len(dest):
                raise AssertionError("shifted bitmap write exceeds destination fixture buffer")
            dest_mask = 0x80 >> (pixel & 7)
            if src_byte & src_mask:
                dest[dest_offset] |= dest_mask
            else:
                dest[dest_offset] &= ~dest_mask


def glyph_source_bytes_for_rows(resources: bytes | bytearray, glyph: dict[str, int | bytes], row_skip: int = 0, rows: int | None = None) -> bytes:
    total_rows = int(glyph["rows"])
    span = int(glyph["render_span"])
    if rows is None:
        rows = total_rows - row_skip
    if row_skip < 0 or rows < 0 or row_skip + rows > total_rows:
        raise AssertionError("glyph source row range is outside the glyph")
    bitmap = int(glyph["bitmap"])
    if glyph_uses_trailing_plane(glyph):
        prefix_span = span - 1
        a2_base = bitmap
        a3_base = bitmap + prefix_span * total_rows
        out = bytearray()
        for row in range(row_skip, row_skip + rows):
            out.extend(resources[a2_base + row * prefix_span : a2_base + (row + 1) * prefix_span])
            out.extend(resources[a3_base + row : a3_base + row + 1])
        return bytes(out)
    start = bitmap + row_skip * span
    return bytes(resources[start : start + rows * span])


def glyph_wide_row_copy_source_bytes(
    data: bytes,
    resources: bytes | bytearray,
    glyph: dict[str, int | bytes],
    row_skip: int = 0,
    rows: int | None = None,
) -> bytes:
    total_rows = int(glyph["rows"])
    render_span = int(glyph["render_span"])
    if rows is None:
        rows = total_rows - row_skip
    if row_skip < 0 or rows < 0 or row_skip + rows > total_rows:
        raise AssertionError("wide glyph source row range is outside the glyph")
    if render_span <= 0x10:
        raise AssertionError("wide glyph source helper expects span above 16 bytes")

    bitmap = int(glyph["bitmap"])
    trailing_plane = glyph_uses_trailing_plane(glyph)
    a2_row_span = render_span - 1 if trailing_plane else render_span
    a2_start = bitmap + row_skip * a2_row_span
    a2_source = bytes(resources[a2_start : a2_start + rows * a2_row_span])
    if trailing_plane:
        a3_base = bitmap + a2_row_span * total_rows
        a3_source = bytes(resources[a3_base + row_skip : a3_base + row_skip + rows])
    else:
        a3_source = b""

    full_chunks = render_span >> 4
    remainder = render_span & 0x0F
    full_row_skip = render_span - (0x11 if remainder & 1 else 0x10)
    remainder_row_skip = render_span - remainder if remainder else 0
    dest = bytearray(rows * render_span)

    def apply_writes(result: RowCopyResult, source_label: str) -> None:
        for write in result.writes:
            if write.source == "A2":
                source = a2_source
            elif write.source == "A3":
                source = a3_source
            else:
                raise AssertionError(f"unexpected {write.source} write for {source_label}")
            if write.src + write.size > len(source):
                raise AssertionError(
                    f"source read past {source_label} {write.source} bitmap at +0x{write.src:x}"
                )
            if write.dst + write.size > len(dest):
                raise AssertionError(
                    f"destination write past {source_label} logical row at +0x{write.dst:x}"
                )
            dest[write.dst : write.dst + write.size] = source[write.src : write.src + write.size]

    for chunk in range(full_chunks):
        apply_writes(
            simulate_row_copy(
                data,
                0x2F27C,
                rows,
                stride=render_span,
                phase=chunk * 0x10,
                source_row_delta=full_row_skip,
            ),
            "wide full-chunk",
        )
    if remainder:
        apply_writes(
            simulate_row_copy(
                data,
                u32(data, 0x1F1AC + remainder * 4),
                rows,
                stride=render_span,
                phase=full_chunks * 0x10,
                source_row_delta=remainder_row_skip,
            ),
            "wide remainder",
        )
    return bytes(dest)


def render_glyph_rows_via_main_row_copy(data: bytes, resources: bytes, glyph: dict[str, int | bytes], dest_stride: int = 0x20) -> list[str]:
    mode = int(glyph["mode"])
    if mode not in (1, 2):
        raise AssertionError(f"mode {mode} row-copy renderer is not implemented")
    rows = int(glyph["rows"])
    width = int(glyph["width"])
    render_span = int(glyph["render_span"])
    if render_span < 1 or render_span > 16:
        raise AssertionError(f"main row-copy table cannot render span {render_span}")
    if render_span & 1 and render_span != 1:
        raise AssertionError("odd multi-byte spans need the A3 trailing-byte fixture before rendering")

    bitmap = int(glyph["bitmap"])
    source = resources[bitmap : bitmap + rows * render_span]
    dest = bytearray(rows * dest_stride)
    result = simulate_row_copy(data, u32(data, 0x1F08E + render_span * 4), rows, stride=dest_stride)
    for write in result.writes:
        if write.source != "A2":
            raise AssertionError(f"unexpected {write.source} write for mode-1 glyph row-copy")
        if write.src + write.size > len(source):
            raise AssertionError(f"source read past glyph bitmap at +0x{write.src:x}")
        if write.dst + write.size > len(dest):
            raise AssertionError(f"destination write past fixture buffer at +0x{write.dst:x}")
        dest[write.dst : write.dst + write.size] = source[write.src : write.src + write.size]
    return bitmap_bytes_to_rows(dest, rows, width, dest_stride)


def builtin_row_copy_span_matrix(data: bytes, resources: bytes, target_spans: tuple[int, ...] = (1, 2, 4, 6, 8)) -> dict[str, object]:
    samples: dict[int, dict[str, object]] = {}
    for base in scanned_builtin_record_bases(resources):
        context = 0x40000000 | (base + 0x80000)
        first_char = u16(resources, base + 0x0E)
        last_char = u16(resources, base + 0x10)
        for glyph_index in range(max(0, last_char - first_char + 1)):
            glyph = resolve_builtin_glyph(resources, context, glyph_index)
            if int(glyph["mode"]) != 1 or int(glyph["rows"]) == 0:
                continue
            render_span = int(glyph["render_span"])
            if render_span not in target_spans or render_span in samples:
                continue
            direct_rows = glyph_bitmap_rows(resources, glyph)
            row_copy_rows = render_glyph_rows_via_main_row_copy(data, resources, glyph)
            samples[render_span] = {
                "context": context,
                "glyph": glyph_index,
                "entry": int(glyph["entry"]),
                "bitmap": int(glyph["bitmap"]),
                "width": int(glyph["width"]),
                "rows": int(glyph["rows"]),
                "span": int(glyph["span"]),
                "render_span": render_span,
                "helper": u32(data, 0x1F08E + render_span * 4),
                "first_rows": direct_rows[:3],
                "last_row": direct_rows[-1] if direct_rows else "",
                "matches": direct_rows == row_copy_rows,
            }
            if set(samples) == set(target_spans):
                break
        if set(samples) == set(target_spans):
            break
    missing = [span for span in target_spans if span not in samples]
    mismatches = [span for span in target_spans if span in samples and not bool(samples[span]["matches"])]
    return {
        "target_spans": target_spans,
        "missing": missing,
        "mismatches": mismatches,
        "samples": [samples[span] for span in target_spans if span in samples],
    }


def render_compact_mode0_payload(data: bytes, resources: bytes, context: int, payload: bytes, dest_stride: int = 0x20, band_rows: int = 64) -> dict[str, object]:
    count = u16(payload, 0)
    pos = 2
    rendered: list[dict[str, int]] = []
    splits: list[dict[str, int]] = []
    dest = bytearray(band_rows * dest_stride)
    fallback_dest = bytearray(band_rows * dest_stride)
    max_width = 0
    max_bottom = 0
    fallback_bottom = 0
    for _ in range(count):
        glyph_index = payload[pos]
        coord = u16(payload, pos + 1)
        pos += 3
        glyph = resolve_compact_glyph(resources, context, glyph_index)
        mode = int(glyph["mode"])
        if mode not in (1, 2):
            raise AssertionError(f"compact mode-0 fixture does not implement glyph mode {mode}")
        rows = int(glyph["rows"])
        width = int(glyph["width"])
        render_span = int(glyph["render_span"])
        row_index = (coord >> 12) & 0x0F
        subbyte = (coord >> 8) & 0x0F
        byte_pair_offset = (coord & 0x00FF) * 2
        x = byte_pair_offset * 8 + subbyte
        rows_in_band = min(rows, max(int(band_rows) - row_index, 0))
        remaining_after_band = rows - rows_in_band
        source = glyph_source_bytes_for_rows(resources, glyph)
        helper = u32(data, 0x1F08E + render_span * 4)
        trailing_plane = glyph_uses_trailing_plane(glyph)
        a2_row_span = render_span - 1 if trailing_plane else render_span
        if rows_in_band:
            result = simulate_row_copy(data, helper, rows_in_band, stride=dest_stride)
            a2_source_len = rows_in_band * a2_row_span
            a3_source_len = rows_in_band if trailing_plane else 0
            for write in result.writes:
                if write.source not in ("A2", "A3"):
                    raise AssertionError(f"unexpected {write.source} write for compact mode-0 glyph")
                source_len = a3_source_len if write.source == "A3" else a2_source_len
                if write.src + write.size > source_len:
                    raise AssertionError(f"source read past compact mode-0 current-band bitmap at +0x{write.src:x}")
            write_bitmap_bits(
                dest,
                dest_stride,
                source[:rows_in_band * render_span],
                rows_in_band,
                render_span,
                x,
                row_index,
            )
        if remaining_after_band:
            result = simulate_row_copy(data, helper, remaining_after_band, stride=dest_stride)
            a2_source_len = remaining_after_band * a2_row_span
            a3_source_len = remaining_after_band if trailing_plane else 0
            for write in result.writes:
                if write.source not in ("A2", "A3"):
                    raise AssertionError(f"unexpected {write.source} write for compact mode-0 fallback glyph")
                source_len = a3_source_len if write.source == "A3" else a2_source_len
                if write.src + write.size > source_len:
                    raise AssertionError(f"source read past compact mode-0 fallback bitmap at +0x{write.src:x}")
            required_fallback = remaining_after_band * dest_stride
            if required_fallback > len(fallback_dest):
                fallback_dest.extend(b"\x00" * (required_fallback - len(fallback_dest)))
            write_bitmap_bits(
                fallback_dest,
                dest_stride,
                source[rows_in_band * render_span:],
                remaining_after_band,
                render_span,
                x,
                0,
            )
        decoded = coord_decode(coord, band_base=0, payload_offset=0)
        rendered.append({
            "glyph": glyph_index,
            "coord": coord,
            "dest_base": decoded["a1"],
            "x": x,
            "y": row_index,
            "a001": decoded["a001"],
            "span": render_span,
            "rows": rows,
            "width": width,
            "helper": helper,
        })
        splits.append({
            "glyph": glyph_index,
            "coord": coord,
            "row_index": row_index,
            "rows": rows,
            "rows_in_band": rows_in_band,
            "remaining_after_band": remaining_after_band,
            "fallback_d2": byte_pair_offset,
        })
        max_width = max(max_width, x + width)
        if rows_in_band:
            max_bottom = max(max_bottom, row_index + rows_in_band)
        fallback_bottom = max(fallback_bottom, remaining_after_band)
    return {
        "count": count,
        "rendered": rendered,
        "splits": splits,
        "rows": bitmap_bytes_to_rows(dest, max_bottom, max_width, dest_stride),
        "fallback_rows": bitmap_bytes_to_rows(fallback_dest, fallback_bottom, max_width, dest_stride),
    }


def validate_wide_compact_row_copy(
    data: bytes,
    rows: int,
    render_span: int,
    trailing_plane: bool,
    full_chunks: int,
    remainder: int,
    full_row_skip: int,
    remainder_row_skip: int,
    dest_stride: int,
    label: str,
) -> None:
    if rows <= 0:
        return
    a2_row_span = render_span - 1 if trailing_plane else render_span
    a2_source_len = a2_row_span * rows
    a3_source_len = rows if trailing_plane else 0
    for chunk in range(full_chunks):
        result = simulate_row_copy(
            data,
            0x2F27C,
            rows,
            stride=dest_stride,
            phase=chunk * 0x10,
            source_row_delta=full_row_skip,
        )
        for write in result.writes:
            if write.source != "A2":
                raise AssertionError(f"unexpected {write.source} write for {label} full chunk")
            if write.src + write.size > a2_source_len:
                raise AssertionError(f"source read past {label} A2 bitmap at +0x{write.src:x}")
    if remainder:
        remainder_helper = u32(data, 0x1F1AC + remainder * 4)
        result = simulate_row_copy(
            data,
            remainder_helper,
            rows,
            stride=dest_stride,
            phase=full_chunks * 0x10,
            source_row_delta=remainder_row_skip,
        )
        for write in result.writes:
            source_len = a3_source_len if write.source == "A3" else a2_source_len
            if write.src + write.size > source_len:
                raise AssertionError(f"source read past {label} {write.source} bitmap at +0x{write.src:x}")


def render_compact_wide_payload_via_1f0d2(data: bytes, resources: bytes | bytearray, context: int, payload: bytes, dest_stride: int = 0x20, band_rows: int = 64) -> dict[str, object]:
    count = u16(payload, 0)
    pos = 2
    rendered: list[dict[str, int | str]] = []
    splits: list[dict[str, int]] = []
    dest = bytearray(band_rows * dest_stride)
    fallback_dest = bytearray(0)
    max_width = 0
    max_bottom = 0
    fallback_bottom = 0
    for _ in range(count):
        glyph_index = payload[pos]
        coord = u16(payload, pos + 1)
        pos += 3
        glyph = resolve_compact_glyph(resources, context, glyph_index)
        mode = int(glyph["mode"])
        if mode not in (1, 2):
            raise AssertionError(f"compact wide fixture does not implement glyph mode {mode}")
        rows = int(glyph["rows"])
        width = int(glyph["width"])
        render_span = int(glyph["render_span"])
        if render_span <= 0x10:
            raise AssertionError("compact wide fixture expects a span wider than one 16-byte chunk")
        row_index = (coord >> 12) & 0x0F
        subbyte = (coord >> 8) & 0x0F
        byte_pair_offset = (coord & 0x00FF) * 2
        x = byte_pair_offset * 8 + subbyte
        rows_in_band = min(rows, max(int(band_rows) - row_index, 0))
        remaining_after_band = rows - rows_in_band

        full_chunks = render_span >> 4
        remainder = render_span & 0x0F
        full_row_skip = render_span - (0x11 if remainder & 1 else 0x10)
        remainder_row_skip = render_span - remainder if remainder else 0
        trailing_plane = glyph_uses_trailing_plane(glyph)

        remainder_helper = 0
        if remainder:
            remainder_helper = u32(data, 0x1F1AC + remainder * 4)

        validate_wide_compact_row_copy(
            data,
            rows_in_band,
            render_span,
            trailing_plane,
            full_chunks,
            remainder,
            full_row_skip,
            remainder_row_skip,
            dest_stride,
            "compact wide current-band",
        )
        if rows_in_band:
            source = glyph_wide_row_copy_source_bytes(data, resources, glyph, rows=rows_in_band)
            write_bitmap_bits(
                dest,
                dest_stride,
                source,
                rows_in_band,
                render_span,
                x,
                row_index,
            )
        validate_wide_compact_row_copy(
            data,
            remaining_after_band,
            render_span,
            trailing_plane,
            full_chunks,
            remainder,
            full_row_skip,
            remainder_row_skip,
            dest_stride,
            "compact wide fallback",
        )
        if remaining_after_band:
            source = glyph_wide_row_copy_source_bytes(
                data,
                resources,
                glyph,
                row_skip=rows_in_band,
                rows=remaining_after_band,
            )
            required_fallback = remaining_after_band * dest_stride
            if required_fallback > len(fallback_dest):
                fallback_dest.extend(b"\x00" * (required_fallback - len(fallback_dest)))
            write_bitmap_bits(
                fallback_dest,
                dest_stride,
                source,
                remaining_after_band,
                render_span,
                x,
                0,
            )
        decoded = coord_decode(coord, band_base=0, payload_offset=0)
        rendered.append({
            "glyph": glyph_index,
            "coord": coord,
            "rows": rows,
            "span": render_span,
            "width": width,
            "full_chunks": full_chunks,
            "remainder": remainder,
            "full_row_skip": full_row_skip,
            "remainder_row_skip": remainder_row_skip,
            "full_chunk_helper": 0x2F27C,
            "remainder_helper": remainder_helper,
            "dest_base": decoded["a1"],
            "x": x,
            "y": row_index,
            "a001": decoded["a001"],
            "source_layout": "inline-trailing-plane" if trailing_plane else "linear",
        })
        splits.append({
            "glyph": glyph_index,
            "coord": coord,
            "row_index": row_index,
            "rows": rows,
            "rows_in_band": rows_in_band,
            "remaining_after_band": remaining_after_band,
            "fallback_d2": byte_pair_offset,
        })
        max_width = max(max_width, x + width)
        if rows_in_band:
            max_bottom = max(max_bottom, row_index + rows_in_band)
        fallback_bottom = max(fallback_bottom, remaining_after_band)
    return {
        "count": count,
        "rendered": rendered,
        "splits": splits,
        "rows": bitmap_bytes_to_rows(dest, max_bottom, max_width, dest_stride),
        "fallback_rows": bitmap_bytes_to_rows(fallback_dest, fallback_bottom, max_width, dest_stride),
    }


def render_compact_segmented_wide_payload_via_1f264(data: bytes, resources: bytes | bytearray, context: int, payload: bytes, dest_stride: int = 0x20, band_rows: int = 16) -> dict[str, object]:
    count = u16(payload, 0)
    pos = 2
    rendered: list[dict[str, int | str]] = []
    splits: list[dict[str, int]] = []
    dest = bytearray(band_rows * dest_stride)
    fallback_dest = bytearray(0)
    max_width = 0
    max_bottom = 0
    fallback_bottom = 0
    for _ in range(count):
        glyph_index = payload[pos]
        segment = payload[pos + 1]
        coord = u16(payload, pos + 2)
        pos += 4
        glyph = resolve_compact_glyph(resources, context, glyph_index)
        mode = int(glyph["mode"])
        if mode not in (1, 2):
            raise AssertionError(f"compact segmented-wide fixture does not implement glyph mode {mode}")
        render_span = int(glyph["render_span"])
        if render_span <= 0x10:
            raise AssertionError("compact segmented-wide fixture expects a span wider than one 16-byte chunk")
        rows_total = int(glyph["rows"])
        row_skip = segment << 7
        if row_skip >= rows_total:
            raise AssertionError("compact segmented-wide fixture segment starts beyond glyph rows")
        rows_here = min(rows_total - row_skip, 0x80)
        row_index = (coord >> 12) & 0x0F
        subbyte = (coord >> 8) & 0x0F
        byte_pair_offset = (coord & 0x00FF) * 2
        x = byte_pair_offset * 8 + subbyte
        rows_in_band = min(rows_here, max(int(band_rows) - row_index, 0))
        remaining_after_band = rows_here - rows_in_band

        full_chunks = render_span >> 4
        remainder = render_span & 0x0F
        full_row_skip = render_span - (0x11 if remainder & 1 else 0x10)
        remainder_row_skip = render_span - remainder if remainder else 0
        trailing_plane = glyph_uses_trailing_plane(glyph)
        a2_row_span = render_span - 1 if trailing_plane else render_span
        a2_source_offset = row_skip * a2_row_span
        a3_source_offset = row_skip if trailing_plane else 0

        remainder_helper = 0
        if remainder:
            remainder_helper = u32(data, 0x1F1AC + remainder * 4)

        validate_wide_compact_row_copy(
            data,
            rows_in_band,
            render_span,
            trailing_plane,
            full_chunks,
            remainder,
            full_row_skip,
            remainder_row_skip,
            dest_stride,
            "compact segmented-wide current-band",
        )
        if rows_in_band:
            source = glyph_wide_row_copy_source_bytes(
                data,
                resources,
                glyph,
                row_skip=row_skip,
                rows=rows_in_band,
            )
            write_bitmap_bits(
                dest,
                dest_stride,
                source,
                rows_in_band,
                render_span,
                x,
                row_index,
            )
        validate_wide_compact_row_copy(
            data,
            remaining_after_band,
            render_span,
            trailing_plane,
            full_chunks,
            remainder,
            full_row_skip,
            remainder_row_skip,
            dest_stride,
            "compact segmented-wide fallback",
        )
        if remaining_after_band:
            source = glyph_wide_row_copy_source_bytes(
                data,
                resources,
                glyph,
                row_skip=row_skip + rows_in_band,
                rows=remaining_after_band,
            )
            required_fallback = remaining_after_band * dest_stride
            if required_fallback > len(fallback_dest):
                fallback_dest.extend(b"\x00" * (required_fallback - len(fallback_dest)))
            write_bitmap_bits(
                fallback_dest,
                dest_stride,
                source,
                remaining_after_band,
                render_span,
                x,
                0,
            )
        decoded = coord_decode(coord, band_base=0, payload_offset=0)
        rendered.append({
            "glyph": glyph_index,
            "segment": segment,
            "coord": coord,
            "row_skip": row_skip,
            "a2_source_offset": a2_source_offset,
            "a3_source_offset": a3_source_offset,
            "rows": rows_here,
            "span": render_span,
            "width": int(glyph["width"]),
            "full_chunks": full_chunks,
            "remainder": remainder,
            "full_row_skip": full_row_skip,
            "remainder_row_skip": remainder_row_skip,
            "full_chunk_helper": 0x2F27C,
            "remainder_helper": remainder_helper,
            "dest_base": decoded["a1"],
            "x": x,
            "y": row_index,
            "a001": decoded["a001"],
            "source_layout": "inline-trailing-plane" if trailing_plane else "linear",
        })
        splits.append({
            "glyph": glyph_index,
            "segment": segment,
            "coord": coord,
            "row_index": row_index,
            "rows": rows_here,
            "rows_in_band": rows_in_band,
            "remaining_after_band": remaining_after_band,
            "fallback_d2": byte_pair_offset,
        })
        max_width = max(max_width, x + int(glyph["width"]))
        if rows_in_band:
            max_bottom = max(max_bottom, row_index + rows_in_band)
        fallback_bottom = max(fallback_bottom, remaining_after_band)
    return {
        "count": count,
        "rendered": rendered,
        "splits": splits,
        "rows": bitmap_bytes_to_rows(dest, max_bottom, max_width, dest_stride),
        "fallback_rows": bitmap_bytes_to_rows(fallback_dest, fallback_bottom, max_width, dest_stride),
    }


def render_compact_segmented_payload_via_1f1f0(data: bytes, resources: bytes | bytearray, context: int, payload: bytes, dest_stride: int = 0x20, band_rows: int = 16) -> dict[str, object]:
    count = u16(payload, 0)
    pos = 2
    rendered: list[dict[str, int | str]] = []
    splits: list[dict[str, int]] = []
    dest = bytearray(band_rows * dest_stride)
    fallback_dest = bytearray(0)
    max_width = 0
    max_bottom = 0
    fallback_bottom = 0
    for _ in range(count):
        glyph_index = payload[pos]
        segment = payload[pos + 1]
        coord = u16(payload, pos + 2)
        pos += 4
        glyph = resolve_compact_glyph(resources, context, glyph_index)
        render_span = int(glyph["render_span"])
        trailing_plane = glyph_uses_trailing_plane(glyph)
        row_skip = segment << 7
        rows_total = int(glyph["rows"])
        if row_skip >= rows_total:
            raise AssertionError("segmented compact fixture segment starts beyond glyph rows")
        rows_here = min(rows_total - row_skip, 0x80)
        row_index = (coord >> 12) & 0x0F
        subbyte = (coord >> 8) & 0x0F
        byte_pair_offset = (coord & 0x00FF) * 2
        x = byte_pair_offset * 8 + subbyte
        rows_in_band = min(rows_here, max(int(band_rows) - row_index, 0))
        remaining_after_band = rows_here - rows_in_band
        bitmap = int(glyph["bitmap"])
        if trailing_plane:
            a2_row_span = render_span - 1
            a2_source_offset = row_skip * a2_row_span
            a3_source_offset = row_skip
            source = glyph_source_bytes_for_rows(resources, glyph, row_skip=row_skip, rows=rows_here)
        else:
            source_offset = row_skip * render_span
            source = resources[bitmap + source_offset : bitmap + source_offset + rows_here * render_span]
        helper = u32(data, 0x1F08E + render_span * 4)
        allowed_sources = ("A2", "A3") if trailing_plane else ("A2",)
        if rows_in_band:
            result = simulate_row_copy(data, helper, rows_in_band, stride=dest_stride)
            for write in result.writes:
                if write.source not in allowed_sources:
                    raise AssertionError(f"unexpected {write.source} write for compact segmented glyph")
                source_len = rows_in_band if write.source == "A3" else rows_in_band * (render_span - 1 if trailing_plane else render_span)
                if write.src + write.size > source_len:
                    raise AssertionError(f"source read past compact segmented current-band bitmap at +0x{write.src:x}")
            write_bitmap_bits(
                dest,
                dest_stride,
                source[:rows_in_band * render_span],
                rows_in_band,
                render_span,
                x,
                row_index,
            )
        if remaining_after_band:
            result = simulate_row_copy(data, helper, remaining_after_band, stride=dest_stride)
            for write in result.writes:
                if write.source not in allowed_sources:
                    raise AssertionError(f"unexpected {write.source} write for compact segmented fallback glyph")
                source_len = remaining_after_band if write.source == "A3" else remaining_after_band * (render_span - 1 if trailing_plane else render_span)
                if write.src + write.size > source_len:
                    raise AssertionError(f"source read past compact segmented fallback bitmap at +0x{write.src:x}")
            required_fallback = remaining_after_band * dest_stride
            if required_fallback > len(fallback_dest):
                fallback_dest.extend(b"\x00" * (required_fallback - len(fallback_dest)))
            write_bitmap_bits(
                fallback_dest,
                dest_stride,
                source[rows_in_band * render_span:],
                remaining_after_band,
                render_span,
                x,
                0,
            )
        decoded = coord_decode(coord, band_base=0, payload_offset=0)
        rendered_entry: dict[str, int | str] = {
            "glyph": glyph_index,
            "segment": segment,
            "coord": coord,
            "row_skip": row_skip,
            "rows": rows_here,
            "span": render_span,
            "width": int(glyph["width"]),
            "dest_base": decoded["a1"],
            "x": x,
            "y": row_index,
            "a001": decoded["a001"],
            "helper": u32(data, 0x1F08E + render_span * 4),
        }
        if trailing_plane:
            rendered_entry.update({
                "a2_source_offset": a2_source_offset,
                "a3_source_offset": a3_source_offset,
                "source_layout": "inline-trailing-plane",
            })
        else:
            rendered_entry["source_offset"] = source_offset
        rendered.append(rendered_entry)
        splits.append({
            "glyph": glyph_index,
            "segment": segment,
            "coord": coord,
            "row_index": row_index,
            "rows": rows_here,
            "rows_in_band": rows_in_band,
            "remaining_after_band": remaining_after_band,
            "fallback_d2": byte_pair_offset,
        })
        max_width = max(max_width, x + int(glyph["width"]))
        if rows_in_band:
            max_bottom = max(max_bottom, row_index + rows_in_band)
        fallback_bottom = max(fallback_bottom, remaining_after_band)
    return {
        "count": count,
        "rendered": rendered,
        "splits": splits,
        "rows": bitmap_bytes_to_rows(dest, max_bottom, max_width, dest_stride),
        "fallback_rows": bitmap_bytes_to_rows(fallback_dest, fallback_bottom, max_width, dest_stride),
    }


def compact_text_coord(x: int, y: int) -> int:
    return ((y & 0x0F) << 12) | ((x & 0x0F) << 8) | ((x >> 4) & 0x00FF)


def pack12(whole: int, frac: int = 0) -> int:
    if not 0 <= frac < 12:
        raise AssertionError(f"packed 12-subunit fraction out of range: {frac}")
    return ((whole & 0xFFFF) << 16) | (frac & 0xFFFF)


def unpack12(value: int) -> tuple[int, int]:
    whole = (value >> 16) & 0xFFFF
    if whole & 0x8000:
        whole -= 0x10000
    frac = value & 0xFFFF
    if frac & 0x8000:
        frac -= 0x10000
    return whole, frac


def packed12_to_subunits(value: int) -> int:
    whole, frac = unpack12(value)
    return whole * 12 + frac


def subunits_to_packed12(value: int) -> int:
    whole, frac = divmod(value, 12)
    return pack12(whole, frac)


def add_packed12(left: int, right: int) -> int:
    return subunits_to_packed12(packed12_to_subunits(left) + packed12_to_subunits(right))


def sub_packed12(left: int, right: int) -> int:
    return subunits_to_packed12(packed12_to_subunits(left) - packed12_to_subunits(right))


def trunc_div(numerator: int, denominator: int) -> int:
    if denominator == 0:
        raise AssertionError("division by zero")
    sign = -1 if numerator < 0 else 1
    return sign * (abs(numerator) // abs(denominator))


def line_termination_mode_bits(parameter: int) -> int:
    value = abs(int(parameter))
    if value == 0:
        return 0x00
    if value == 1:
        return 0x80
    if value == 2:
        return 0x60
    if value == 3:
        return 0xE0
    raise AssertionError("ESC &k#G fixture only models accepted values 0..3")


def apply_hmi_via_ca8c(state: dict[str, int], integer: int, fraction: int = 0) -> dict[str, int]:
    updated = dict(state)
    events = list(updated.get("events", []))
    whole = abs(int(integer))
    frac = abs(int(fraction))
    before = int(updated.get("hmi", 0))
    stored = False
    if whole <= 0x348:
        updated["hmi"] = parsed_decimal_scaled_to_packed12(whole, frac, 30)
        updated["printable_advance"] = updated["hmi"]
        stored = True
    events.append({
        "kind": "hmi",
        "parameter": int(integer),
        "fraction": int(fraction),
        "hmi_before": before,
        "hmi_after": int(updated.get("hmi", before)),
        "stored": stored,
    })
    updated["events"] = events
    return updated


def control_fixture_state(**overrides: int) -> dict[str, int]:
    state = {
        "cursor_x": pack12(10),
        "cursor_y": pack12(20),
        "left_margin": pack12(5),
        "right_limit": pack12(100),
        "page_width": 120,
        "hmi": pack12(2),
        "vmi": pack12(3),
        "pending_width": 1,
        "right_limit_latch": 1,
        "pending_text": 1,
        "line_termination": 0,
        "span_flush_enable": 0,
        "alternate_metrics": 0,
        "previous_width_word": 0,
        "page_roots": 0,
        "page_finalizes": 0,
        "span_flushes": 0,
        "post_flushes": 0,
        "span_updates": 0,
    }
    state.update(overrides)
    return state


def control_cr_helper(state: dict[str, int]) -> None:
    state["cursor_x"] = state["left_margin"]
    state["right_limit_latch"] = 0
    state["pending_text"] = 0


def control_text_flush_helper(state: dict[str, int]) -> None:
    state["pending_width"] = 0
    if state["span_flush_enable"]:
        state["span_flushes"] += 1
        state["post_flushes"] += 1


def rearm_text_span_via_126e2(state: dict[str, object]) -> dict[str, object]:
    if int(state.get("enabled_783184", 0)):
        return {
            "rearmed": False,
            "reason": "already-enabled",
            "enabled_783184": int(state.get("enabled_783184", 0)),
        }
    cursor_x = unpack12(int(state.get("cursor_x", 0)))[0]
    state["enabled_783184"] = 1
    state["high_x_783188"] = cursor_x
    state["low_x_783186"] = cursor_x
    state["high_y_78318a"] = 0
    state["span_flush_enable"] = 1
    return {
        "rearmed": True,
        "enabled_783184": 1,
        "low_x_783186": cursor_x,
        "high_x_783188": cursor_x,
        "high_y_78318a": 0,
    }


def control_text_flush_helper_with_page_record(
    state: dict[str, object],
    page_record: dict[str, object] | None,
) -> dict[str, object] | None:
    before_flushes = int(state.get("span_flushes", 0))
    control_text_flush_helper(state)  # type: ignore[arg-type]
    if (
        page_record is None
        or not int(state.get("materialize_span_flush", 0))
        or int(state.get("span_flushes", 0)) == before_flushes
    ):
        return None

    span_state = {
        "enabled_783184": int(state.get("enabled_783184", 0)),
        "low_x_783186": int(state.get("low_x_783186", 0)),
        "high_x_783188": int(state.get("high_x_783188", 0)),
        "high_y_78318a": int(state.get("high_y_78318a", 0)),
        "orientation_782da3": int(state.get("orientation", state.get("orientation_782da3", 0))),
        "orientation_extent_782db2": int(state.get("orientation_extent_782db2", 0)),
        "page_extent_782db6": int(state.get("page_extent_782db6", 0xFFFF)),
    }
    flushed = flush_text_span_via_12714(
        page_record,
        span_state,
        vertical_offset=int(state.get("span_vertical_offset_782dc0", 0)),
    )
    flushed_state = flushed.get("state", {})
    if isinstance(flushed_state, dict):
        state["enabled_783184"] = int(flushed_state.get("enabled_783184", 0))
        state["low_x_783186"] = int(flushed_state.get("low_x_783186", span_state["low_x_783186"]))
        state["high_x_783188"] = int(flushed_state.get("high_x_783188", span_state["high_x_783188"]))
        state["high_y_78318a"] = int(flushed_state.get("high_y_78318a", span_state["high_y_78318a"]))
    rearmed = rearm_text_span_via_126e2(state)
    flushed["rearm"] = rearmed
    return flushed


def update_flagged_span_via_d8fc(
    page_record: dict[str, object],
    state: dict[str, object],
    resources: bytes | bytearray | None = None,
    context: int | None = None,
) -> dict[str, object]:
    if not int(state.get("enabled_783184", 0)):
        return {"updated": False, "reason": "disabled"}

    cursor_y = unpack12(int(state.get("cursor_y", 0)))[0]
    metric_source: dict[str, object]
    if int(state.get("span_metrics_from_context", 0)):
        if resources is None or context is None:
            raise AssertionError("d8fc context metric fixture requires resources and context")
        address = int(context) & 0x00FFFFFF
        base_bias = 0x80000 if 0x80000 <= address < 0xC0000 else 0
        base = address - base_bias
        if base + 0x1B >= len(resources):
            raise AssertionError("flagged context span fields outside resource image")
        lower = u16(resources, base + 0x16)
        height = u16(resources, base + 0x18)
        alternate_offset = u16(resources, base + 0x1A)
        metric_source = {
            "kind": "context",
            "base": base,
            "context": int(context),
        }
    else:
        lower = int(state.get("flagged_context_0016", 0))
        height = int(state.get("flagged_context_0018", 0))
        alternate_offset = int(state.get("flagged_context_001a", 0))
        metric_source = {"kind": "state"}
    if cursor_y < lower:
        return {"updated": False, "reason": "before-context-lower", "cursor_y": cursor_y}

    page_extent = int(state.get("page_extent_782db6", state.get("page_extent", 0xFFFF)))
    if cursor_y + height > page_extent:
        return {"updated": False, "reason": "beyond-page-extent", "cursor_y": cursor_y}

    if int(state.get("span_alternate_offset_783185", 0)):
        high_y = cursor_y - alternate_offset
    else:
        high_y = cursor_y + 5
    if high_y > int(state.get("high_y_78318a", 0)):
        state["high_y_78318a"] = high_y

    cursor_x = unpack12(int(state.get("cursor_x", 0)))[0]
    flush_result: dict[str, object] | None = None
    if cursor_x < int(state.get("low_x_783186", 0)):
        flush_result = control_text_flush_helper_with_page_record(state, page_record)
    if cursor_x > int(state.get("high_x_783188", 0)):
        state["high_x_783188"] = cursor_x

    return {
        "updated": True,
        "handler": 0x00D8FC,
        "cursor_x": cursor_x,
        "cursor_y": cursor_y,
        "context_lower_0016": lower,
        "context_height_0018": height,
        "context_offset_001a": alternate_offset,
        "high_y": high_y,
        "metric_source": metric_source,
        "flush_result": flush_result,
        "state": {
            "enabled_783184": int(state.get("enabled_783184", 0)),
            "low_x_783186": int(state.get("low_x_783186", 0)),
            "high_x_783188": int(state.get("high_x_783188", 0)),
            "high_y_78318a": int(state.get("high_y_78318a", 0)),
        },
    }


def update_unflagged_span_via_d4ac(
    resources: bytes,
    page_record: dict[str, object],
    state: dict[str, object],
    context: int,
) -> dict[str, object]:
    if not int(state.get("enabled_783184", 0)):
        return {"updated": False, "reason": "disabled"}

    base = int(context) & 0x00FFFFFF
    if base + 0x2D >= len(resources):
        raise AssertionError("unflagged context span fields outside resource image")

    cursor_y = unpack12(int(state.get("cursor_y", 0)))[0]
    lower = resources[base + 0x2C]
    if cursor_y < lower:
        return {"updated": False, "reason": "before-context-lower", "cursor_y": cursor_y}

    height = resources[base + 0x2D]
    page_extent = int(state.get("page_extent_782db6", state.get("page_extent", 0xFFFF)))
    if cursor_y + height > page_extent:
        return {"updated": False, "reason": "beyond-page-extent", "cursor_y": cursor_y}

    alternate_offset = resources[base + 0x2B]
    if int(state.get("span_alternate_offset_783185", 0)) and alternate_offset:
        high_y = cursor_y + alternate_offset
    else:
        high_y = cursor_y + 5
    if high_y > int(state.get("high_y_78318a", 0)):
        state["high_y_78318a"] = high_y

    cursor_x = unpack12(int(state.get("cursor_x", 0)))[0]
    flush_result: dict[str, object] | None = None
    if cursor_x < int(state.get("low_x_783186", 0)):
        flush_result = control_text_flush_helper_with_page_record(state, page_record)
    if cursor_x > int(state.get("high_x_783188", 0)):
        state["high_x_783188"] = cursor_x

    return {
        "updated": True,
        "handler": 0x00D4AC,
        "cursor_x": cursor_x,
        "cursor_y": cursor_y,
        "context_offset_002b": alternate_offset,
        "context_lower_002c": lower,
        "context_height_002d": height,
        "high_y": high_y,
        "flush_result": flush_result,
        "state": {
            "enabled_783184": int(state.get("enabled_783184", 0)),
            "low_x_783186": int(state.get("low_x_783186", 0)),
            "high_x_783188": int(state.get("high_x_783188", 0)),
            "high_y_78318a": int(state.get("high_y_78318a", 0)),
        },
    }


def control_lf_helper(state: dict[str, int]) -> None:
    state["page_roots"] += 1
    state["cursor_y"] = add_packed12(state["cursor_y"], state["vmi"])
    state["pending_text"] = 0


def control_ff_helper(state: dict[str, int]) -> None:
    state["page_finalizes"] += 1
    state["pending_text"] = 0


def control_ff_page_record_helper(state: dict[str, int], page_record: dict[str, object]) -> dict[str, object]:
    state = dict(state)
    if state["line_termination"] & 0x20:
        control_cr_helper(state)
    control_text_flush_helper(state)
    state["page_roots"] += 1
    finalized = finalize_page_record_via_ff1e(page_record, state)
    state["page_finalizes"] += 1
    state["pending_text"] = 0xFF
    state["current_page_root"] = int(finalized["current_page_root_after"])
    state["page_root_clears"] = int(finalized["page_root_clears"])
    if finalized["published"]:
        state["transient_page_byte"] = int(finalized["transient_page_byte"])
        state["cursor_transient_a"] = int(finalized["cursor_transient_a"])
        state["cursor_transient_b"] = int(finalized["cursor_transient_b"])
        state["page_publication_flag"] = int(finalized["page_publication_flag"])
        state["page_publications"] = int(state.get("page_publications", 0)) + 1
        state["published_pool_record"] = 1
    return {
        "state": state,
        "finalized_page_record": finalized,
    }


def control_page_eject_via_f124(state: dict[str, int], page_record: dict[str, object]) -> dict[str, object]:
    state = dict(state)
    finalized = finalize_page_record_via_ff1e(page_record, state)
    state["page_finalizes"] = int(state.get("page_finalizes", 0)) + 1
    state["pending_text"] = 0
    state["cursor_y"] = pending_text_cursor_for_vmi(
        int(state["top_offset"]),
        int(state["vmi"]),
    )
    state["current_page_root"] = int(finalized["current_page_root_after"])
    state["page_root_present"] = 0
    state["page_root_class"] = 0
    state["page_root_clears"] = int(finalized["page_root_clears"])
    if finalized["published"]:
        state["transient_page_byte"] = int(finalized["transient_page_byte"])
        state["cursor_transient_a"] = int(finalized["cursor_transient_a"])
        state["cursor_transient_b"] = int(finalized["cursor_transient_b"])
        state["page_publication_flag"] = int(finalized["page_publication_flag"])
        state["page_publications"] = int(state.get("page_publications", 0)) + 1
        state["published_pool_record"] = 1
    return {
        "state": state,
        "finalized_page_record": finalized,
    }


def vfc_bottom_recovery_cursor_via_12afc(
    top_offset: int,
    vmi: int,
    last_line: int,
    target_line: int,
) -> int:
    vmi_subunits = packed12_to_subunits(vmi)
    line_gap_subunits = (int(last_line) - int(target_line) + 1) * vmi_subunits
    baseline_bias_subunits = trunc_div(vmi_subunits * 18, 25)
    return add_packed12(
        int(top_offset),
        subunits_to_packed12(line_gap_subunits - baseline_bias_subunits),
    )


def control_span_update(state: dict[str, int]) -> None:
    state["span_updates"] += 1


def apply_direct_control_code(
    state: dict[str, int],
    code: int,
    page_record: dict[str, object] | None = None,
) -> dict[str, int]:
    state = dict(state)
    last_span_flush_result: dict[str, object] | None = None
    if code == 0x0D:  # CR
        control_cr_helper(state)
        last_span_flush_result = control_text_flush_helper_with_page_record(state, page_record)
        if state["line_termination"] & 0x80:
            control_lf_helper(state)
    elif code == 0x0A:  # LF
        if state["line_termination"] & 0x40:
            control_cr_helper(state)
        last_span_flush_result = control_text_flush_helper_with_page_record(state, page_record)
        control_lf_helper(state)
    elif code == 0x0C:  # FF
        if state["line_termination"] & 0x20:
            control_cr_helper(state)
        last_span_flush_result = control_text_flush_helper_with_page_record(state, page_record)
        state["page_roots"] += 1
        control_ff_helper(state)
        state["pending_text"] = 0xFF
    elif code == 0x09:  # HT
        hmi_subunits = packed12_to_subunits(state["hmi"])
        if hmi_subunits == 0:
            return state
        if state["cursor_x"] < state["left_margin"]:
            next_cursor = state["left_margin"]
        else:
            distance = packed12_to_subunits(sub_packed12(state["cursor_x"], state["left_margin"]))
            tab_index = ((distance // hmi_subunits) & ~0x07) + 8
            next_cursor = add_packed12(state["left_margin"], subunits_to_packed12(tab_index * hmi_subunits))
        limit = pack12(state["page_width"]) if state["cursor_x"] > state["right_limit"] else state["right_limit"]
        if next_cursor > limit:
            next_cursor = limit
        state["cursor_x"] = next_cursor
        state["right_limit_latch"] = 1 if next_cursor == state["right_limit"] else 0
        state["pending_text"] = 0
        control_span_update(state)
    elif code == 0x08:  # BS
        amount = pack12(state["previous_width_word"]) if state["alternate_metrics"] else state["hmi"]
        next_cursor = sub_packed12(state["cursor_x"], amount)
        next_subunits = packed12_to_subunits(next_cursor)
        left_subunits = packed12_to_subunits(state["left_margin"])
        if state["cursor_x"] >= state["left_margin"] and next_subunits < left_subunits:
            next_cursor = state["left_margin"]
        if next_subunits < 0:
            next_cursor = 0
        state["cursor_x"] = next_cursor
        state["pending_width"] = 1
        state["right_limit_latch"] = 0
        state["pending_text"] = 0
        control_span_update(state)
    else:
        raise AssertionError(f"unsupported direct control fixture byte 0x{code:02x}")
    if last_span_flush_result is not None:
        state["last_span_flush_result"] = last_span_flush_result  # type: ignore[assignment]
    else:
        state.pop("last_span_flush_result", None)  # type: ignore[arg-type]
    return state


