def font_sample_extent_via_1c6a4_1c6da(
    resources: bytes,
    record_start: int,
    context: int,
) -> dict[str, int]:
    mode1 = 1 if (int(context) & 0x40000000) else 0
    if mode1:
        return {
            "selector_flag_1c766": 1,
            "line_advance_1c6a4": u16(resources, record_start + 0x16),
            "row_height_1c6da": u16(resources, record_start + 0x18),
        }
    return {
        "selector_flag_1c766": 0,
        "line_advance_1c6a4": resources[record_start + 0x2C],
        "row_height_1c6da": resources[record_start + 0x2D],
    }


def line_advance_subunits_via_1cfe4(
    line_advance_1c6a4: int,
    row_height_cache_783f06: int,
) -> int:
    value = int(line_advance_1c6a4) + int(row_height_cache_783f06)
    advanced = signed_divide_trunc_via_3324a(value * 0x75 * 0x0C, 0x64)
    return max(0x0258, advanced)


def font_sample_run2_transition_via_1cf34(
    resources: bytes,
    row_fields: dict[str, object],
    state: dict[str, int],
    *,
    alternate_record_start: int | None = None,
    alternate_context: int | None = None,
    row_height_cache_783f06: int | None = None,
    page_limit_782db6: int = 0x7FFF,
) -> dict[str, object]:
    record_start = int(row_fields["record_start"])
    context = int(row_fields["context"])
    if alternate_record_start is None:
        alternate_record_start = record_start
    if alternate_context is None:
        alternate_context = context

    current_extent = font_sample_extent_via_1c6a4_1c6da(
        resources,
        record_start,
        context,
    )
    alternate_extent = font_sample_extent_via_1c6a4_1c6da(
        resources,
        int(alternate_record_start),
        int(alternate_context),
    )
    if row_height_cache_783f06 is None:
        row_height_cache_783f06 = current_extent["row_height_1c6da"]

    before = dict(state)
    line_anchor_x = int(state.get("line_anchor_x", pack12(0)))
    state["cursor_x"] = line_anchor_x
    state["pending_cursor_x_782a57"] = 0
    state["pending_flag_782a6d"] = 0

    line_advance_subunits = line_advance_subunits_via_1cfe4(
        current_extent["line_advance_1c6a4"],
        int(row_height_cache_783f06),
    )
    state["cursor_y"] = subunits_to_packed12(
        packed12_to_subunits(int(state["cursor_y"])) + line_advance_subunits
    )
    state["row_height_cache_783f06"] = max(
        current_extent["row_height_1c6da"],
        alternate_extent["row_height_1c6da"],
    )
    continuation_needed = (
        unpack12(int(state["cursor_y"]))[0] + int(state["row_height_cache_783f06"])
        >= int(page_limit_782db6)
    )

    advance = advance_flagged_text_cursor_via_d550(
        state["cursor_x"],
        pack12(0x31 * 30),
    )
    state["cursor_x"] = advance["cursor_after"]
    return {
        "helper": "0x1cf34/0x1d050/0x1cfe4",
        "flush_0xf06e": {
            "cursor_before": before["cursor_x"],
            "line_anchor_x_782dd6": line_anchor_x,
            "cursor_after": line_anchor_x,
        },
        "current_extent": current_extent,
        "alternate_extent": alternate_extent,
        "row_height_cache_before_783f06": int(row_height_cache_783f06),
        "line_advance_subunits_1cfe4": line_advance_subunits,
        "cursor_y_before": before["cursor_y"],
        "cursor_y_after": state["cursor_y"],
        "row_height_cache_after_783f06": state["row_height_cache_783f06"],
        "page_limit_782db6": int(page_limit_782db6),
        "continuation_needed": continuation_needed,
        "gap_advance_1d152": advance,
    }


def font_sample_row_to_row_transition_via_1d050(
    resources: bytes,
    selected_row_fields: dict[str, object],
    current_record_start: int,
    current_context: int,
    state: dict[str, int],
    *,
    source_index: int | None = None,
    row_index: int | None = None,
    row_height_cache_783f06: int | None = None,
    page_limit_782db6: int = 0x7FFF,
) -> dict[str, object]:
    selected_extent = font_sample_extent_via_1c6a4_1c6da(
        resources,
        int(selected_row_fields["record_start"]),
        int(selected_row_fields["context"]),
    )
    current_extent = font_sample_extent_via_1c6a4_1c6da(
        resources,
        int(current_record_start),
        int(current_context),
    )
    if row_height_cache_783f06 is None:
        row_height_cache_783f06 = int(state.get(
            "row_height_cache_783f06",
            selected_extent["row_height_1c6da"],
        ))

    before = dict(state)
    line_anchor_x = int(state.get("line_anchor_x", pack12(0)))
    state["cursor_x"] = line_anchor_x
    state["pending_cursor_x_782a57"] = 0
    state["pending_flag_782a6d"] = 0

    row_height_after = max(
        selected_extent["row_height_1c6da"],
        current_extent["row_height_1c6da"],
    )
    line_advance_subunits = line_advance_subunits_via_1cfe4(
        selected_extent["line_advance_1c6a4"],
        int(row_height_cache_783f06),
    )
    state["cursor_y"] = subunits_to_packed12(
        packed12_to_subunits(int(state["cursor_y"])) + line_advance_subunits
    )
    state["row_height_cache_783f06"] = row_height_after
    continuation_needed = (
        unpack12(int(state["cursor_y"]))[0] + row_height_after
        >= int(page_limit_782db6)
    )
    result = {
        "helper": "0x1d050/0x1cfe4",
        "flush_0xf06e": {
            "cursor_before": before["cursor_x"],
            "line_anchor_x_782dd6": line_anchor_x,
            "cursor_after": line_anchor_x,
        },
        "selected_extent": selected_extent,
        "current_extent": current_extent,
        "row_height_cache_before_783f06": int(row_height_cache_783f06),
        "line_advance_subunits_1cfe4": line_advance_subunits,
        "cursor_y_before": before["cursor_y"],
        "cursor_y_after": state["cursor_y"],
        "row_height_cache_after_783f06": row_height_after,
        "page_limit_782db6": int(page_limit_782db6),
        "continuation_needed": continuation_needed,
    }
    if continuation_needed:
        result["continuation_call"] = {
            "taken": True,
            "reason": "page-limit-after-row-advance",
            "page_reset": "0x1c9f6",
            "heading_call": {
                "target": "0x1ca2c",
                "source_index": source_index,
                "row_index": row_index,
                "current_context": int(current_context),
                "selected_context": int(selected_row_fields["context"]),
            },
            "second_advance": {
                "target": "0x1cfe4",
                "line_advance_units": selected_extent["line_advance_1c6a4"],
                "line_advance_subunits": line_advance_subunits,
            },
        }
    return result


def font_sample_alternate_row_projection_via_1d8ba(
    resources: bytes,
    selected_record_start: int,
    selected_context: int,
    current_record_start: int,
    current_context: int,
    *,
    cursor_y: int,
    page_limit_782db6: int,
) -> dict[str, object]:
    selected_extent = font_sample_extent_via_1c6a4_1c6da(
        resources,
        int(selected_record_start),
        int(selected_context),
    )
    current_extent = font_sample_extent_via_1c6a4_1c6da(
        resources,
        int(current_record_start),
        int(current_context),
    )
    line_advance_subunits = line_advance_subunits_via_1cfe4(
        selected_extent["line_advance_1c6a4"],
        selected_extent["row_height_1c6da"],
    )
    projected_y = subunits_to_packed12(
        packed12_to_subunits(int(cursor_y)) + line_advance_subunits
    )
    projected_y_word = unpack12(projected_y)[0]
    row_height_after = max(
        selected_extent["row_height_1c6da"],
        current_extent["row_height_1c6da"],
    )
    projected_bottom = projected_y_word + row_height_after
    continuation_needed = int(page_limit_782db6) <= projected_bottom
    return {
        "helper": "0x1d8ba",
        "selected_record_start": int(selected_record_start),
        "selected_context": int(selected_context),
        "current_record_start": int(current_record_start),
        "current_context": int(current_context),
        "selected_extent": selected_extent,
        "current_extent": current_extent,
        "cursor_y_782c8e": int(cursor_y),
        "line_advance_subunits_1cfe4": line_advance_subunits,
        "projected_y": projected_y,
        "projected_y_word": projected_y_word,
        "row_height_after": row_height_after,
        "projected_bottom": projected_bottom,
        "page_limit_782db6": int(page_limit_782db6),
        "continuation_needed": continuation_needed,
    }


def font_sample_alternate_row_fit_gate_via_1d868(
    resources: bytes,
    selected_record_start: int,
    selected_context: int,
    current_record_start: int,
    current_context: int,
    *,
    row_index: int,
    selected_flag_783132: int,
    cursor_y: int,
    page_limit_782db6: int,
) -> dict[str, object]:
    result: dict[str, object] = {
        "helper": "0x1d868",
        "selected_record_start": int(selected_record_start),
        "selected_context": int(selected_context),
        "current_record_start": int(current_record_start),
        "current_context": int(current_context),
        "row_index": int(row_index),
        "selected_flag_783132": int(selected_flag_783132),
        "cursor_y_782c8e": int(cursor_y),
        "page_limit_782db6": int(page_limit_782db6),
        "setup_calls": [
            {
                "target": "0x1cece",
                "record_start": int(selected_record_start),
                "context": int(selected_context),
                "row_index": int(row_index),
            },
            {
                "target": "0x1c5e8",
                "record_start": int(current_record_start),
                "context": int(current_context),
            },
        ],
    }
    if int(selected_flag_783132) == 0:
        result["projection_call"] = None
        result["continuation_needed"] = False
        result["return_d7"] = 0
        return result

    projection = font_sample_alternate_row_projection_via_1d8ba(
        resources,
        int(selected_record_start),
        int(selected_context),
        int(current_record_start),
        int(current_context),
        cursor_y=int(cursor_y),
        page_limit_782db6=int(page_limit_782db6),
    )
    continuation_needed = bool(projection["continuation_needed"])
    result["projection_call"] = projection
    result["continuation_needed"] = continuation_needed
    result["return_d7"] = 1 if continuation_needed else 0
    return result


def font_sample_row_projection_via_1dc38(
    resources: bytes,
    selected_record_start: int,
    selected_context: int,
    current_record_start: int,
    current_context: int,
    *,
    cursor_y: int,
    mode: int,
) -> dict[str, object]:
    selected_extent = font_sample_extent_via_1c6a4_1c6da(
        resources,
        int(selected_record_start),
        int(selected_context),
    )
    current_extent = font_sample_extent_via_1c6a4_1c6da(
        resources,
        int(current_record_start),
        int(current_context),
    )
    row_height_source = (
        current_extent["row_height_1c6da"]
        if int(mode) == 1
        else selected_extent["row_height_1c6da"]
    )
    line_advance_subunits = line_advance_subunits_via_1cfe4(
        selected_extent["line_advance_1c6a4"],
        row_height_source,
    )
    extra_mode1_subunits = 0x0258 if int(mode) == 1 else 0
    total_subunits = line_advance_subunits + extra_mode1_subunits
    projected_y = subunits_to_packed12(
        packed12_to_subunits(int(cursor_y)) + total_subunits
    )
    projected_y_word = unpack12(projected_y)[0]
    row_height_after = max(row_height_source, current_extent["row_height_1c6da"])
    projected_bottom = projected_y_word + row_height_after
    return {
        "helper": "0x1dc38",
        "selected_record_start": int(selected_record_start),
        "selected_context": int(selected_context),
        "current_record_start": int(current_record_start),
        "current_context": int(current_context),
        "mode": int(mode),
        "selected_extent": selected_extent,
        "current_extent": current_extent,
        "cursor_y_before": int(cursor_y),
        "row_height_source": row_height_source,
        "line_advance_subunits_1cfe4": line_advance_subunits,
        "extra_mode1_subunits": extra_mode1_subunits,
        "total_advance_subunits": total_subunits,
        "projected_y": projected_y,
        "projected_y_word": projected_y_word,
        "row_height_after": row_height_after,
        "projected_bottom": projected_bottom,
    }


def add_font_sample_probe_limit(
    probe: dict[str, object],
    page_limit_782db6: int,
) -> dict[str, object]:
    with_limit = dict(probe)
    with_limit["page_limit_782db6"] = int(page_limit_782db6)
    with_limit["overruns_page_limit"] = (
        int(page_limit_782db6) <= int(probe["projected_bottom"])
    )
    return with_limit


def font_sample_multi_probe_preflight_via_1dcf2(
    resources: bytes,
    selected_record_start: int,
    selected_context: int,
    current_record_start: int,
    current_context: int,
    *,
    row_index: int,
    selected_flag_783132: int,
    cursor_y: int,
    page_limit_782db6: int,
) -> dict[str, object]:
    probes: list[dict[str, object]] = []

    def probe(cursor: int, mode: int, label: str) -> dict[str, object]:
        event = add_font_sample_probe_limit(
            font_sample_row_projection_via_1dc38(
                resources,
                int(selected_record_start),
                int(selected_context),
                int(current_record_start),
                int(current_context),
                cursor_y=int(cursor),
                mode=int(mode),
            ),
            int(page_limit_782db6),
        )
        event["label"] = label
        probes.append(event)
        return event

    first = probe(int(cursor_y), 0, "initial-current-y")
    branch = "first-overrun" if bool(first["overruns_page_limit"]) else "first-fits"
    return_label = ""
    return_d7 = 0
    reset_y: int | None = None

    def run_reset_sequence() -> bool:
        nonlocal return_d7, return_label, reset_y
        reset_y = subunits_to_packed12(0x1218)
        reset_mode1 = probe(reset_y, 1, "reset-y-mode1")
        if bool(reset_mode1["overruns_page_limit"]):
            return_d7 = 1
            return_label = "0x1de24"
            return True
        if int(selected_flag_783132) == 0:
            return_d7 = 0
            return_label = "0x1de28"
            return True
        reset_mode0 = probe(int(reset_mode1["projected_y"]), 0, "reset-y-mode0")
        if bool(reset_mode0["overruns_page_limit"]):
            return_d7 = 1
            return_label = "0x1de2c"
        else:
            return_d7 = 0
            return_label = "0x1de16"
        return True

    if bool(first["overruns_page_limit"]):
        run_reset_sequence()
    elif int(selected_flag_783132) == 0:
        return_d7 = 0
        return_label = "0x1de1a"
    else:
        second = probe(int(first["projected_y"]), 0, "second-selected-row")
        if bool(second["overruns_page_limit"]):
            branch = "second-overrun"
            run_reset_sequence()
        else:
            branch = "two-rows-fit"
            return_d7 = 0
            return_label = "0x1dd8e"

    return {
        "helper": "0x1dcf2",
        "selected_record_start": int(selected_record_start),
        "selected_context": int(selected_context),
        "current_record_start": int(current_record_start),
        "current_context": int(current_context),
        "row_index": int(row_index),
        "selected_flag_783132": int(selected_flag_783132),
        "cursor_y_782c8e": int(cursor_y),
        "page_limit_782db6": int(page_limit_782db6),
        "setup_calls": [
            {
                "target": "0x1cece",
                "record_start": int(selected_record_start),
                "context": int(selected_context),
                "row_index": int(row_index),
            },
            {
                "target": "0x1c5e8",
                "record_start": int(current_record_start),
                "context": int(current_context),
            },
        ],
        "reset_y_from_raw_0x1218": reset_y,
        "branch": branch,
        "probes": probes,
        "return_label": return_label,
        "return_d7": return_d7,
    }


def render_font_sample_first_row_fields_and_both_runs_page_record(
    data: bytes,
    resources: bytes,
    row_fields: dict[str, object],
) -> dict[str, object]:
    row_page = render_font_sample_first_row_fields_and_run1_page_record(
        data,
        resources,
        row_fields,
    )
    page_record = row_page["page_record"]
    state = dict(row_page["final_state"])  # type: ignore[arg-type]
    assert isinstance(page_record, dict)
    context = int(row_fields["context"])
    transition = font_sample_run2_transition_via_1cf34(
        resources,
        row_fields,
        state,  # type: ignore[arg-type]
    )
    sample_run2 = bytes.fromhex(
        "a1 a2 b3 b4 b6 b8 b9 bb bd c1 c5 c8 c9 cd ce d0 d2 d4 "
        "d7 d8 db de e0 e3 e8"
    )
    sample_event = queue_font_sample_printable_chunk_to_page_record(
        resources,
        context,
        page_record,
        state,  # type: ignore[arg-type]
        sample_run2,
        "sample-run-2",
        pack12(30),
    )
    bucket_objects = page_record_bucket_objects(page_record)
    object_hashes = {
        bucket: [hashlib.sha256(obj).hexdigest() for obj in objects]
        for bucket, objects in bucket_objects.items()
    }
    return {
        "context": context,
        "run1": row_page,
        "transition": transition,
        "sample_event": sample_event,
        "sample_run2": sample_run2,
        "nonempty_buckets": sorted(bucket_objects),
        "bucket_objects": bucket_objects,
        "bucket_object_hashes": object_hashes,
        "final_cursor_x": state["cursor_x"],
        "final_cursor_y": state["cursor_y"],
        "final_state": dict(state),
        "page_record": page_record,
    }


