    def mixed_metric_stream(
        first_code: int,
        range_word: int,
        rounded_word: int,
        offset_byte: int,
    ) -> bytearray:
        stream = bytearray(font_validate_stream)
        stream[6:8] = first_code.to_bytes(2, "big")
        stream[10:12] = range_word.to_bytes(2, "big")
        stream[20:22] = rounded_word.to_bytes(2, "big")
        stream[30] = offset_byte
        return stream

