    def downloaded_partial_visible_report(
        *,
        command_stream: bytes,
        char_code: int,
        record_words: tuple[int, int, int, int],
        width: int,
        rows: int,
        object_offset: int,
    ) -> dict[str, object]:
        combined_stream = command_stream + bytes([char_code])
        fetched = fetch_stream_via_a904(
            host_byte_fetch_state(ring=list(combined_stream), direct_mode=0),
            len(combined_stream),
        )
        resource_stream = fetched["stream"][:len(command_stream)]
        printable_stream = fetched["stream"][len(command_stream):]
        resource_trace = trace_font_parser_dispatch_via_11774(data, resource_stream)
        resource_command = render_font_download_char_command_stream_via_121cc_16498(
            resource_stream,
            table_payload_type2_bytes,
            char_code=char_code,
            record_words=record_words,
            mode=1,
            width=width,
            rows=rows,
            object_offset=object_offset,
        )
        resource_event = resource_command["events"][0]
        assert isinstance(resource_event, dict)
        install = resource_event["install"]
        assert isinstance(install, dict)
        memory = bytearray(install["header"])
        glyph = resolve_downloaded_pointer_glyph(memory, 0, char_code)
        assert glyph is not None
        printable_trace = trace_mixed_text_control_parser_path_via_11774(
            data,
            printable_stream,
        )
        copy = install["copy"]
        assert isinstance(copy, dict)
        return_drain = consume_data_payload_count_via_12328(
            int(copy["byte_budget"]),
            printable_stream,
        )
        source = {
            "context": 0,
            "host_char": printable_stream[0],
            "mapped": char_code,
            "glyph_entry": glyph["entry"],
            "glyph_width": glyph["width"],
            "glyph_rows": glyph["rows"],
            "flag": 0,
            "x": 22,
            "y": 22,
            "context_slot": 3,
            "inline_record": bytes([
                int(glyph["render_span"]),
                int(glyph["rows"]) & 0xFF,
                0,
            ]),
        }
        page_record: dict[str, object] = {
            "bucket_array": {},
            "context_slots": [0, 0, 0, 0],
        }
        page_result = queue_text_source_to_page_record_via_12f2e(
            memory,
            page_record,
            source,
        )
        render_entry = render_bucket_page_record_via_1ed84_1ef6a(
            data,
            memory,
            page_record,
            bucket_word=int(page_result["bucket_index"]),
        )
        entry = render_entry["entry"]
        assert isinstance(entry, dict)
        finalized = finalize_page_record_via_ff1e(
            page_record,
            reset_fixture_state(
                page_root_present=1,
                page_root_class=1,
                current_page_root=ABSTRACT_PAGE_ROOT_PTR,
                page_root_clears=0,
                publication_bucket_index=int(page_result["bucket_index"]),
            ),
        )
        published = finalized["published_pool_record"]
        assert isinstance(published, dict)
        published_fields = published["pool_record_fields"]
        assert isinstance(published_fields, dict)
        published_render = render_published_page_record_via_1ed84_1ef6a(
            data,
            memory,
            published,
            bucket_word=int(page_result["bucket_index"]),
        )
        published_entry = published_render["entry"]
        assert isinstance(published_entry, dict)
        return {
            "combined_length": len(fetched["stream"]),
            "fetch_source_set": sorted(set(fetched["sources"])),
            "remaining_ring": fetched["state"]["ring"],
            "resource": {
                "parser_handlers": [
                    event["handler"]
                    for event in resource_trace["dispatches"]
                ],
                "restored_record": resource_event["restored_record"],
                "payload_offset": resource_event["payload_offset"],
                "payload_length": resource_event["payload_length"],
                "install_status": install["status"],
                "table_entry": install["table_entry"],
                "table_pointer": u32(memory, int(install["table_entry"])),
                "return_boundary": {
                    "call_edge": (0x15DC6, 0x16498),
                    "return_edge": (0x16498, 0x15DCC),
                    "drain_edge": (0x15DCC, 0x12328),
                    "remaining_budget_0x783140": copy["byte_budget"],
                    "drain": return_drain,
                    "next_stream_prefix": printable_stream[:1],
                    "next_handler": printable_trace["events"][0]["handler"],
                },
                "bitmap": bytes(
                    memory[
                        int(install["bitmap_offset"]):
                        int(install["bitmap_offset"]) + int(install["expected_bitmap_size"])
                    ]
                ),
                "continuation": install["continuation"],
            },
            "printable": {
                "stream": printable_stream,
                "parser_handlers": [
                    event["handler"]
                    for event in printable_trace["events"]
                ],
                "source": {
                    key: source[key]
                    for key in (
                        "host_char",
                        "mapped",
                        "glyph_entry",
                        "glyph_width",
                        "glyph_rows",
                        "inline_record",
                    )
                },
                "page": {
                    key: page_result[key]
                    for key in ("path", "selector", "coord", "glyph", "rows", "width")
                },
                "bucket_index": page_result["bucket_index"],
                "object": page_result["object"],
                "dispatch": [
                    {
                        key: dispatch[key]
                        for key in (
                            "chain_index",
                            "object_byte_4",
                            "class_mask",
                            "branch",
                            "target",
                            "context_slot",
                        )
                    }
                    for dispatch in entry["dispatch"]["entries"]
                ],
                "rows": entry["rows"],
            },
            "publication": {
                "ff_handlers": [
                    event["handler"]
                    for event in trace_mixed_text_control_parser_path_via_11774(
                        data,
                        b"\x0c",
                    )["events"]
                ],
                "finalized": {
                    "published": finalized["published"],
                    "bucket_index": finalized["bucket_index"],
                    "current_page_root_after": finalized["current_page_root_after"],
                    "page_root_clears": finalized["page_root_clears"],
                    "page_publication_flag": finalized["page_publication_flag"],
                },
                "published_bucket_root": published_fields["bucket_root_1c"],
                "published_bucket_array": published_fields["bucket_array_1c"],
                "published_context_slots": published_fields["context_slots_2c"][:4],
                "render_bucket_word": published_render["render_record_fields"]["word_10"],
                "active_copy": published_render["active_copy"],
                "setup": {
                    key: published_entry["setup"][key]
                    for key in (
                        "dividend",
                        "divisor_word_06",
                        "remainder_783a22",
                        "band_rows_scaled_783a20",
                        "destination_base_783a28",
                    )
                },
                "call_order": published_entry["call_order"],
                "dispatch": [
                    {
                        key: dispatch[key]
                        for key in (
                            "chain_index",
                            "object_byte_4",
                            "class_mask",
                            "branch",
                            "target",
                            "context_slot",
                        )
                    }
                    for dispatch in published_entry["dispatch"]["entries"]
                ],
                "rows": published_entry["rows"],
            },
        }

